const GRAMMAR = [
{"id":"alfavit-proiznoshenie","icon":"🔤","level":"A1","title":{"ru":"Алфавит и произношение","de":"Alphabet und Aussprache","en":"Alphabet and pronunciation","fr":"Alphabet et prononciation","fa":"الفبا و تلفظ","uk":"Абетка й вимова","ar_sy":"الأبجدية واللفظ"},"intro":{"ru":"Русский язык использует кириллицу — 33 буквы. Ударение свободное и очень важно: безударная «о» звучит как «а» (это редукция гласных). Согласные бывают твёрдыми и мягкими; мягкость показывают буквы е, ё, и, ю, я и мягкий знак ь.","de":"Russisch benutzt das kyrillische Alphabet mit 33 Buchstaben. Die Betonung ist frei und sehr wichtig: Ein unbetontes «о» klingt wie «а» (Vokalreduktion). Konsonanten sind hart oder weich; die Weichheit zeigen е, ё, и, ю, я und das Weichheitszeichen ь.","en":"Russian uses the Cyrillic alphabet — 33 letters. Stress is free and very important: an unstressed «о» sounds like «а» (vowel reduction). Consonants are hard or soft; softness is shown by е, ё, и, ю, я and the soft sign ь.","fr":"Le russe utilise l'alphabet cyrillique — 33 lettres. L'accent tonique est libre et très important : un «о» non accentué se prononce «а» (réduction vocalique). Les consonnes sont dures ou molles ; la mollesse est indiquée par е, ё, и, ю, я et le signe mou ь.","fa":"روسی از الفبای سیریلیک با ۳۳ حرف استفاده می‌کند. تکیه آزاد و بسیار مهم است: «о» بدون تکیه مانند «а» تلفظ می‌شود (کاهش مصوت). صامت‌ها سخت یا نرم‌اند؛ نرمی را حروف е، ё، и، ю، я و نشانهٔ نرم ь نشان می‌دهند.","uk":"Російська використовує кирилицю — 33 літери. Наголос вільний і дуже важливий: ненаголошене «о» звучить як «а» (редукція голосних). Приголосні бувають твердими й м'якими; м'якість показують е, ё, и, ю, я та м'який знак ь.","ar_sy":"الروسي بيستعمل الأبجدية السيريلية — ٣٣ حرف. النبرة حرة وكتير مهمة: الـ«о» يلي ما عليها نبرة بتنلفظ متل «а» (تخفيف الحركات). الحروف الساكنة إما قاسية أو ناعمة؛ النعومة بتبيّنها الحروف е، ё، и، ю، я ونشانة النعومة ь."},"tables":[{"caption":{"ru":"Некоторые буквы и звуки","de":"Einige Buchstaben und Laute","en":"Some letters and sounds","fr":"Quelques lettres et sons","fa":"برخی حروف و صداها","uk":"Деякі літери та звуки","ar_sy":"بعض الحروف والأصوات"},"labelHeader":{"ru":"Буква","de":"Buchstabe","en":"Letter","fr":"Lettre","fa":"حرف","uk":"Літера","ar_sy":"الحرف"},"columns":[{"ru":"Звук","de":"Laut","en":"Sound","fr":"Son","fa":"صدا","uk":"Звук","ar_sy":"الصوت"},{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"Б","de":"Б","en":"Б","fr":"Б","fa":"Б","uk":"Б","ar_sy":"Б"},"cells":["[b] как «б»","банк"]},{"label":{"ru":"В","de":"В","en":"В","fr":"В","fa":"В","uk":"В","ar_sy":"В"},"cells":["[v] как «в»","вода"]},{"label":{"ru":"Ж","de":"Ж","en":"Ж","fr":"Ж","fa":"Ж","uk":"Ж","ar_sy":"Ж"},"cells":["[ʐ] как «ж»","жена"]},{"label":{"ru":"Х","de":"Х","en":"Х","fr":"Х","fa":"Х","uk":"Х","ar_sy":"Х"},"cells":["[x] как «х»","хлеб"]},{"label":{"ru":"Ы","de":"Ы","en":"Ы","fr":"Ы","fa":"Ы","uk":"Ы","ar_sy":"Ы"},"cells":["[ɨ] задний «и»","сын"]},{"label":{"ru":"Ц","de":"Ц","en":"Ц","fr":"Ц","fa":"Ц","uk":"Ц","ar_sy":"Ц"},"cells":["[ts] как «ц»","цена"]}]},{"caption":{"ru":"Редукция гласной «о»","de":"Reduktion des Vokals «о»","en":"Reduction of the vowel «о»","fr":"Réduction de la voyelle «о»","fa":"کاهش مصوت «о»","uk":"Редукція голосного «о»","ar_sy":"تخفيف الحركة «о»"},"labelHeader":{"ru":"Слово","de":"Wort","en":"Word","fr":"Mot","fa":"کلمه","uk":"Слово","ar_sy":"الكلمة"},"columns":[{"ru":"Ударение","de":"Betonung","en":"Stress","fr":"Accent","fa":"تکیه","uk":"Наголос","ar_sy":"النبرة"},{"ru":"Произношение","de":"Aussprache","en":"Pronunciation","fr":"Prononciation","fa":"تلفظ","uk":"Вимова","ar_sy":"اللفظ"}],"rows":[{"label":{"ru":"молоко","de":"молоко","en":"молоко","fr":"молоко","fa":"молоко","uk":"молоко","ar_sy":"молоко"},"cells":["молокó","[məlakó]"]},{"label":{"ru":"хорошо","de":"хорошо","en":"хорошо","fr":"хорошо","fa":"хорошо","uk":"хорошо","ar_sy":"хорошо"},"cells":["хорошó","[xərašó]"]},{"label":{"ru":"окно","de":"окно","en":"окно","fr":"окно","fa":"окно","uk":"окно","ar_sy":"окно"},"cells":["окнó","[aknó]"]}]}],"examples":[{"ru":"Как тебя зовут?","de":"Wie heißt du?","en":"What's your name?","fr":"Comment tu t'appelles ?","fa":"اسمت چیه؟","uk":"Як тебе звати?","ar_sy":"شو اسمك؟"},{"ru":"Я не говорю по-русски.","de":"Ich spreche kein Russisch.","en":"I don't speak Russian.","fr":"Je ne parle pas russe.","fa":"من روسی صحبت نمی‌کنم.","uk":"Я не розмовляю російською.","ar_sy":"أنا ما بحكي روسي."},{"ru":"Повторите, пожалуйста, медленно.","de":"Wiederholen Sie bitte langsam.","en":"Please repeat slowly.","fr":"Répétez lentement, s'il vous plaît.","fa":"لطفاً آهسته تکرار کنید.","uk":"Повторіть, будь ласка, повільно.","ar_sy":"عيد بشوي، لو سمحت."}],"hints":{"de":"«е», «и», «н» sehen wie lateinische Buchstaben aus, klingen aber anders: «н» = [n], «р» = [r], «с» = [s]. Verwechsle sie nicht mit e, u, H.","en":"«н», «р», «с», «в» look like Latin H, P, C, B but sound like [n], [r], [s], [v]. Don't read them as English letters.","fr":"Attention aux « faux amis » graphiques : «н»=[n], «р»=[r], «с»=[s], «в»=[v]. Le «р» russe est roulé, pas guttural comme le r français.","fa":"روسی نبرهٔ واژه‌ها متغیر است و باید حفظ شود؛ مثل فارسی که همیشه روی هجای آخر نیست. حرف «х» مانند «خ» فارسی است.","uk":"Літери майже ті самі, але немає ґ, є, і, ї; натомість є ы, ъ, э. Російське ненаголошене «о» вимовляється як «а», на відміну від української.","ar_sy":"الروسي في حروف ما إلها مقابل بالعربي متل «п»=[p] و«в»=[v]؛ ميّزهن. النبرة بتغيّر معنى الكلمة، فاحفظها مع كل كلمة."}},
{"id":"rod-sushchestvitelnyh","icon":"🚻","level":"A1","title":{"ru":"Род существительных","de":"Genus der Substantive","en":"Gender of nouns","fr":"Genre des noms","fa":"جنس اسم‌ها","uk":"Рід іменників","ar_sy":"جنس الأسماء"},"intro":{"ru":"У русских существительных три рода: мужской, женский и средний. Обычно род виден по окончанию: согласный — мужской, «-а/-я» — женский, «-о/-е» — средний. Артиклей в русском нет: «дом» значит и «дом», и «a/the house».","de":"Russische Substantive haben drei Genera: männlich, weiblich, sächlich. Das Genus erkennt man meist an der Endung: Konsonant — männlich, «-а/-я» — weiblich, «-о/-е» — sächlich. Artikel gibt es im Russischen nicht: «дом» heißt sowohl «Haus» als auch «ein/das Haus».","en":"Russian nouns have three genders: masculine, feminine, neuter. Gender is usually visible from the ending: a consonant — masculine, «-а/-я» — feminine, «-о/-е» — neuter. Russian has no articles: «дом» means both «house» and «a/the house».","fr":"Les noms russes ont trois genres : masculin, féminin, neutre. Le genre se voit généralement à la terminaison : consonne — masculin, «-а/-я» — féminin, «-о/-е» — neutre. Le russe n'a pas d'articles : «дом» signifie à la fois « maison » et « une/la maison ».","fa":"اسم‌های روسی سه جنس دارند: مذکر، مؤنث، خنثی. جنس معمولاً از پایانهٔ کلمه پیداست: صامت — مذکر، «-а/-я» — مؤنث، «-о/-е» — خنثی. روسی حرف تعریف ندارد: «дом» هم یعنی «خانه» و هم «یک/آن خانه».","uk":"Російські іменники мають три роди: чоловічий, жіночий, середній. Рід зазвичай видно із закінчення: приголосний — чоловічий, «-а/-я» — жіночий, «-о/-е» — середній. Артиклів у російській немає: «дом» означає і «дім», і «a/the house».","ar_sy":"الأسماء الروسية إلها ثلاث أجناس: مذكر، مؤنث، ومحايد. الجنس عادةً بيبيّن من آخر الكلمة: حرف ساكن — مذكر، «-а/-я» — مؤنث، «-о/-е» — محايد. الروسي ما في أدوات تعريف: «дом» يعني «بيت» و«البيت» بنفس الوقت."},"tables":[{"caption":{"ru":"Род по окончанию","de":"Genus nach der Endung","en":"Gender by ending","fr":"Genre selon la terminaison","fa":"جنس بر اساس پایانه","uk":"Рід за закінченням","ar_sy":"الجنس حسب النهاية"},"labelHeader":{"ru":"Род","de":"Genus","en":"Gender","fr":"Genre","fa":"جنس","uk":"Рід","ar_sy":"الجنس"},"columns":[{"ru":"Окончание","de":"Endung","en":"Ending","fr":"Terminaison","fa":"پایانه","uk":"Закінчення","ar_sy":"النهاية"},{"ru":"Примеры","de":"Beispiele","en":"Examples","fr":"Exemples","fa":"مثال‌ها","uk":"Приклади","ar_sy":"أمثلة"}],"rows":[{"label":{"ru":"мужской","de":"männlich","en":"masculine","fr":"masculin","fa":"مذکر","uk":"чоловічий","ar_sy":"مذكر"},"cells":["согласный, -й","дом, стол, музей"]},{"label":{"ru":"женский","de":"weiblich","en":"feminine","fr":"féminin","fa":"مؤنث","uk":"жіночий","ar_sy":"مؤنث"},"cells":["-а, -я","мама, вода, неделя"]},{"label":{"ru":"средний","de":"sächlich","en":"neuter","fr":"neutre","fa":"خنثی","uk":"середній","ar_sy":"محايد"},"cells":["-о, -е","окно, море, письмо"]},{"label":{"ru":"на -ь","de":"auf -ь","en":"ending in -ь","fr":"en -ь","fa":"پایان به -ь","uk":"на -ь","ar_sy":"ينتهي بـ -ь"},"cells":["-ь (м. или ж.)","день (м), ночь (ж)"]}]}],"examples":[{"ru":"Это мой дом.","de":"Das ist mein Haus.","en":"This is my house.","fr":"C'est ma maison.","fa":"این خانهٔ من است.","uk":"Це мій дім.","ar_sy":"هادا بيتي."},{"ru":"Вода холодная.","de":"Das Wasser ist kalt.","en":"The water is cold.","fr":"L'eau est froide.","fa":"آب سرد است.","uk":"Вода холодна.","ar_sy":"الماي باردة."},{"ru":"Окно открыто.","de":"Das Fenster ist offen.","en":"The window is open.","fr":"La fenêtre est ouverte.","fa":"پنجره باز است.","uk":"Вікно відчинене.","ar_sy":"الشباك مفتوح."}],"hints":{"de":"Anders als im Deutschen ist das Genus meist an der Endung ablesbar und muss selten stur auswendig gelernt werden. Vorsicht bei «-ь»-Wörtern: da hilft die Endung nicht.","en":"Unlike German or French, you rarely memorize gender blindly — the ending usually tells you. The tricky group is nouns ending in «-ь», which can be masculine or feminine.","fr":"Contrairement au français, il n'y a pas d'article pour signaler le genre : c'est la terminaison qui le montre. Attention, le genre russe ne correspond pas toujours au genre français (une «проблема» est féminine, mais «un problème» est masculin).","fa":"فارسی جنس دستوری ندارد، پس این مفهوم تازه است. خبر خوب: پایانهٔ کلمه معمولاً جنس را نشان می‌دهد و لازم نیست همه را حفظ کنید.","uk":"Система роду майже така сама, як в українській, тож інтуїція здебільшого працює. Але деякі слова мають інший рід: рос. «собака» — жін., «біль» — чол.","ar_sy":"بالعربي في مذكر ومؤنث بس، أما بالروسي في تالت جنس «محايد». الخبر المنيح إنو آخر الكلمة عادةً بيقلك الجنس، فما لازم تحفظ كلشي."}},
{"id":"lichnye-mestoimeniya","icon":"🫵","level":"A1","title":{"ru":"Личные местоимения","de":"Personalpronomen","en":"Personal pronouns","fr":"Pronoms personnels","fa":"ضمایر شخصی","uk":"Особові займенники","ar_sy":"الضمائر الشخصية"},"intro":{"ru":"Личные местоимения: я, ты, он, она, оно, мы, вы, они. «Он/она/оно» выбирают по роду существительного, а не по одушевлённости. «Ты» — для друзей, семьи и детей; «вы» — вежливое обращение к незнакомым и старшим, а также ко многим людям.","de":"Personalpronomen: я, ты, он, она, оно, мы, вы, они. «Он/она/оно» richten sich nach dem Genus des Substantivs, nicht nach belebt/unbelebt. «Ты» für Freunde, Familie und Kinder; «вы» als höfliche Anrede an Fremde und Ältere sowie an mehrere Personen.","en":"Personal pronouns: я, ты, он, она, оно, мы, вы, они. «Он/она/оно» agree with the noun's gender, not with animacy. «Ты» is for friends, family and children; «вы» is the polite form for strangers and elders, and also plural «you».","fr":"Pronoms personnels : я, ты, он, она, оно, мы, вы, они. «Он/она/оно» s'accordent avec le genre du nom, pas avec l'animé/inanimé. «Ты» pour les amis, la famille et les enfants ; «вы» est la forme polie pour les inconnus et les aînés, et aussi le « vous » pluriel.","fa":"ضمایر شخصی: я، ты، он، она، оно، мы، вы، они. «он/она/оно» با جنس اسم مطابقت می‌کنند، نه با جانداری. «ты» برای دوستان، خانواده و کودکان؛ «вы» شکل مؤدبانه برای غریبه‌ها و بزرگ‌ترها و نیز «شما»ی جمع است.","uk":"Особові займенники: я, ты, он, она, оно, мы, вы, они. «Он/она/оно» узгоджуються з родом іменника, а не з істотою/неістотою. «Ты» — до друзів, родини й дітей; «вы» — ввічлива форма до незнайомих і старших, а також множина «ви».","ar_sy":"الضمائر الشخصية: я، ты، он، она، оно، мы، вы، они. «он/она/оно» بيتبعوا جنس الاسم، مو إذا كان عاقل أو لأ. «ты» للأصحاب والعيلة والولاد؛ «вы» صيغة الاحترام للغرباء والأكبر سنّاً، وكمان «إنتو» للجمع."},"tables":[{"caption":{"ru":"Личные местоимения","de":"Personalpronomen","en":"Personal pronouns","fr":"Pronoms personnels","fa":"ضمایر شخصی","uk":"Особові займенники","ar_sy":"الضمائر الشخصية"},"labelHeader":{"ru":"Лицо","de":"Person","en":"Person","fr":"Personne","fa":"شخص","uk":"Особа","ar_sy":"الشخص"},"columns":[{"ru":"Единственное","de":"Singular","en":"Singular","fr":"Singulier","fa":"مفرد","uk":"Однина","ar_sy":"المفرد"},{"ru":"Множественное","de":"Plural","en":"Plural","fr":"Pluriel","fa":"جمع","uk":"Множина","ar_sy":"الجمع"}],"rows":[{"label":{"ru":"1-е","de":"1.","en":"1st","fr":"1re","fa":"اول","uk":"1-ша","ar_sy":"الأول"},"cells":["я","мы"]},{"label":{"ru":"2-е","de":"2.","en":"2nd","fr":"2e","fa":"دوم","uk":"2-га","ar_sy":"الثاني"},"cells":["ты","вы"]},{"label":{"ru":"3-е","de":"3.","en":"3rd","fr":"3e","fa":"سوم","uk":"3-тя","ar_sy":"الثالث"},"cells":["он / она / оно","они"]}]},{"caption":{"ru":"«Ты» или «вы»?","de":"«Ты» oder «вы»?","en":"«Ты» or «вы»?","fr":"«Ты» ou «вы» ?","fa":"«ты» یا «вы»؟","uk":"«Ты» чи «вы»?","ar_sy":"«ты» ولا «вы»؟"},"labelHeader":{"ru":"Форма","de":"Form","en":"Form","fr":"Forme","fa":"صیغه","uk":"Форма","ar_sy":"الصيغة"},"columns":[{"ru":"Когда","de":"Wann","en":"When","fr":"Quand","fa":"چه زمانی","uk":"Коли","ar_sy":"إيمتى"}],"rows":[{"label":{"ru":"ты","de":"ты","en":"ты","fr":"ты","fa":"ты","uk":"ты","ar_sy":"ты"},"cells":["друзья, семья, дети, ровесники"]},{"label":{"ru":"вы","de":"вы","en":"вы","fr":"вы","fa":"вы","uk":"вы","ar_sy":"вы"},"cells":["незнакомые, старшие, начальник, много людей"]}]}],"examples":[{"ru":"Ты студент?","de":"Bist du Student?","en":"Are you a student?","fr":"Tu es étudiant ?","fa":"تو دانشجویی؟","uk":"Ти студент?","ar_sy":"إنت طالب؟"},{"ru":"Извините, вы говорите по-английски?","de":"Entschuldigung, sprechen Sie Englisch?","en":"Excuse me, do you speak English?","fr":"Excusez-moi, parlez-vous anglais ?","fa":"ببخشید، شما انگلیسی صحبت می‌کنید؟","uk":"Вибачте, ви розмовляєте англійською?","ar_sy":"عفواً، إنتو بتحكوا إنكليزي؟"},{"ru":"Они наши друзья.","de":"Sie sind unsere Freunde.","en":"They are our friends.","fr":"Ce sont nos amis.","fa":"آن‌ها دوستان ما هستند.","uk":"Вони наші друзі.","ar_sy":"هنّي رفقاتنا."}],"hints":{"de":"«Вы» entspricht dem deutschen höflichen «Sie», wird aber im Satz als Plural behandelt (Verb auf «-ете»). «Оно» gibt es im Deutschen als «es», bezieht sich hier aber nur auf sächliche Substantive.","en":"«Вы» is like the polite form English lost — use it with strangers and elders. Note «он/она» also mean «it» for masculine/feminine objects: a table (стол) is «он», not «оно».","fr":"«Ты/вы» fonctionne comme «tu/vous» en français, la distinction est presque identique. Mais «он/она» servent aussi pour les objets : une table (стол, masc.) se dit «он», pas «elle» ni «оно».","fa":"فارسی «تو/شما» را دارد، پس تفاوت «ты/вы» آشناست. توجه: «он/она» برای اشیاء هم به کار می‌روند؛ یک شیء مذکر «он» و یک شیء مؤنث «она» است.","uk":"Майже тотожно українському «ти/ви». Пам'ятайте: «оно» вживається лише для середнього роду, тоді як предмети чол./жін. роду — це «он/она».","ar_sy":"بالعربي ما في فرق بين «إنت» رسمي وغير رسمي متل الروسي؛ «вы» بتنستعمل للاحترام ومتل «حضرتك». وانتبه: «он/она» بتنستعملوا كمان للأشياء حسب جنسها، مو بس للبشر."}},
{"id":"nastoyashchee-vremya","icon":"⏱️","level":"A1","title":{"ru":"Настоящее время","de":"Präsens","en":"Present tense","fr":"Présent","fa":"زمان حال","uk":"Теперішній час","ar_sy":"المضارع"},"intro":{"ru":"В настоящем времени русские глаголы делятся на два спряжения. У 1-го спряжения гласный «-е-» в окончаниях (читать: читаю, читаешь), у 2-го — «-и-» (говорить: говорю, говоришь). Глагол «быть» в настоящем времени опускается: «Я студент» = «Я есть студент».","de":"Im Präsens teilen sich russische Verben in zwei Konjugationen. Die 1. hat den Vokal «-е-» in den Endungen (читать: читаю, читаешь), die 2. hat «-и-» (говорить: говорю, говоришь). Das Verb «быть» (sein) entfällt im Präsens: «Я студент» = «Ich (bin) Student».","en":"In the present tense Russian verbs fall into two conjugations. The 1st has the vowel «-е-» in its endings (читать: читаю, читаешь), the 2nd has «-и-» (говорить: говорю, говоришь). The verb «быть» (to be) is omitted in the present: «Я студент» = «I (am) a student».","fr":"Au présent, les verbes russes se répartissent en deux conjugaisons. La 1re a la voyelle «-е-» dans ses terminaisons (читать : читаю, читаешь), la 2e a «-и-» (говорить : говорю, говоришь). Le verbe «быть» (être) est omis au présent : «Я студент» = « Je (suis) étudiant ».","fa":"در زمان حال، افعال روسی به دو صرف تقسیم می‌شوند. صرف اول مصوت «-е-» در پایانه دارد (читать: читаю, читаешь) و صرف دوم «-и-» (говорить: говорю, говоришь). فعل «быть» (بودن) در زمان حال حذف می‌شود: «Я студент» یعنی «من دانشجو (هستم)».","uk":"У теперішньому часі російські дієслова поділяються на дві дієвідміни. Перша має голосний «-е-» в закінченнях (читать: читаю, читаешь), друга — «-и-» (говорить: говорю, говоришь). Дієслово «быть» (бути) у теперішньому часі випускається: «Я студент» = «Я (є) студент».","ar_sy":"بالمضارع، الأفعال الروسية بتنقسم لتصريفين. الأول عندو الحرف «-е-» بالنهايات (читать: читаю، читаешь)، والثاني عندو «-и-» (говорить: говорю، говоришь). فعل «быть» (يكون) بينحذف بالمضارع: «Я студент» يعني «أنا (هوّي) طالب»."},"tables":[{"caption":{"ru":"1-е спряжение: читать","de":"1. Konjugation: читать (lesen)","en":"1st conjugation: читать (to read)","fr":"1re conjugaison : читать (lire)","fa":"صرف اول: читать (خواندن)","uk":"1-ша дієвідміна: читать (читати)","ar_sy":"التصريف الأول: читать (يقرأ)"},"labelHeader":{"ru":"Местоимение","de":"Pronomen","en":"Pronoun","fr":"Pronom","fa":"ضمیر","uk":"Займенник","ar_sy":"الضمير"},"columns":[{"ru":"читать (-е-)","de":"читать (-е-)","en":"читать (-е-)","fr":"читать (-е-)","fa":"читать (-е-)","uk":"читать (-е-)","ar_sy":"читать (-е-)"}],"rows":[{"label":{"ru":"я","de":"я","en":"я","fr":"я","fa":"я","uk":"я","ar_sy":"я"},"cells":["читаю"]},{"label":{"ru":"ты","de":"ты","en":"ты","fr":"ты","fa":"ты","uk":"ты","ar_sy":"ты"},"cells":["читаешь"]},{"label":{"ru":"он/она","de":"он/она","en":"он/она","fr":"он/она","fa":"он/она","uk":"он/она","ar_sy":"он/она"},"cells":["читает"]},{"label":{"ru":"мы","de":"мы","en":"мы","fr":"мы","fa":"мы","uk":"мы","ar_sy":"мы"},"cells":["читаем"]},{"label":{"ru":"вы","de":"вы","en":"вы","fr":"вы","fa":"вы","uk":"вы","ar_sy":"вы"},"cells":["читаете"]},{"label":{"ru":"они","de":"они","en":"они","fr":"они","fa":"они","uk":"они","ar_sy":"они"},"cells":["читают"]}]},{"caption":{"ru":"2-е спряжение: говорить","de":"2. Konjugation: говорить (sprechen)","en":"2nd conjugation: говорить (to speak)","fr":"2e conjugaison : говорить (parler)","fa":"صرف دوم: говорить (صحبت کردن)","uk":"2-га дієвідміна: говорить (говорити)","ar_sy":"التصريف الثاني: говорить (يحكي)"},"labelHeader":{"ru":"Местоимение","de":"Pronomen","en":"Pronoun","fr":"Pronom","fa":"ضمیر","uk":"Займенник","ar_sy":"الضمير"},"columns":[{"ru":"говорить (-и-)","de":"говорить (-и-)","en":"говорить (-и-)","fr":"говорить (-и-)","fa":"говорить (-и-)","uk":"говорить (-и-)","ar_sy":"говорить (-и-)"}],"rows":[{"label":{"ru":"я","de":"я","en":"я","fr":"я","fa":"я","uk":"я","ar_sy":"я"},"cells":["говорю"]},{"label":{"ru":"ты","de":"ты","en":"ты","fr":"ты","fa":"ты","uk":"ты","ar_sy":"ты"},"cells":["говоришь"]},{"label":{"ru":"он/она","de":"он/она","en":"он/она","fr":"он/она","fa":"он/она","uk":"он/она","ar_sy":"он/она"},"cells":["говорит"]},{"label":{"ru":"мы","de":"мы","en":"мы","fr":"мы","fa":"мы","uk":"мы","ar_sy":"мы"},"cells":["говорим"]},{"label":{"ru":"вы","de":"вы","en":"вы","fr":"вы","fa":"вы","uk":"вы","ar_sy":"вы"},"cells":["говорите"]},{"label":{"ru":"они","de":"они","en":"они","fr":"они","fa":"они","uk":"они","ar_sy":"они"},"cells":["говорят"]}]}],"examples":[{"ru":"Я читаю книгу.","de":"Ich lese ein Buch.","en":"I am reading a book.","fr":"Je lis un livre.","fa":"من کتاب می‌خوانم.","uk":"Я читаю книжку.","ar_sy":"أنا عم إقرأ كتاب."},{"ru":"Ты говоришь по-русски?","de":"Sprichst du Russisch?","en":"Do you speak Russian?","fr":"Tu parles russe ?","fa":"تو روسی صحبت می‌کنی؟","uk":"Ти розмовляєш російською?","ar_sy":"إنت بتحكي روسي؟"},{"ru":"Он инженер.","de":"Er ist Ingenieur.","en":"He is an engineer.","fr":"Il est ingénieur.","fa":"او مهندس است.","uk":"Він інженер.","ar_sy":"هوّي مهندس."}],"hints":{"de":"Es gibt nur eine Präsensform — «читаю» heißt sowohl «ich lese» als auch «ich lese gerade». Denk daran, «быть» wegzulassen: nicht «Я есть студент», sondern «Я студент».","en":"There's only one present form — «читаю» covers both «I read» and «I am reading». Don't insert a «to be» verb: say «Я студент», never «Я есть студент».","fr":"Il n'y a qu'une forme de présent : «читаю» rend à la fois « je lis » et « je suis en train de lire ». Ne mettez pas de verbe « être » : dites «Я студент», jamais «Я есть студент».","fa":"فقط یک شکل زمان حال وجود دارد؛ «читаю» هم «می‌خوانم» است و هم «دارم می‌خوانم». فعل ربطی «هستن» را نیاورید: بگویید «Я студент»، نه «Я есть студент».","uk":"На відміну від англійської, форма одна: «читаю» = і «читаю», і «читаю зараз». Не ставте «быть»: правильно «Я студент», а не «Я є студент».","ar_sy":"في بس صيغة وحدة للمضارع؛ «читаю» يعني «بقرأ» و«عم إقرأ» سوا. ما تحط فعل «يكون»: قول «Я студент»، مو «Я есть студент»."}},
{"id":"byt-imenitelnyy","icon":"🟰","level":"A1","title":{"ru":"Именительный падеж и глагол «быть»","de":"Nominativ und das Verb «sein»","en":"Nominative case and the verb “to be”","fr":"Le nominatif et le verbe « être »","fa":"حالت نهادی و فعل «بودن»","uk":"Називний відмінок і дієслово «бути»","ar_sy":"حالة المبتدأ وفعل «كان/يكون»"},"intro":{"ru":"Именительный падеж — это начальная форма слова (кто? что?). В настоящем времени глагол «быть» не произносится: «Я студент». Указывают на предмет словом «это», а «у меня есть» значит «я имею».","de":"Der Nominativ ist die Grundform des Wortes (wer? was?). Im Präsens wird das Verb «sein» weggelassen: «Я студент» = «Ich bin Student». Mit «это» zeigt man auf etwas, und «у меня есть» bedeutet «ich habe».","en":"The nominative is the dictionary form of a word (who? what?). In the present tense the verb “to be” is dropped: «Я студент» = “I am a student”. «Это» points to something, and «у меня есть» means “I have”.","fr":"Le nominatif est la forme de base du mot (qui ? quoi ?). Au présent, le verbe « être » est omis : « Я студент » = « Je suis étudiant ». « Это » désigne une chose, et « у меня есть » signifie « j'ai ».","fa":"حالت نهادی شکل پایه‌ی واژه است (چه کسی؟ چه چیزی؟). در زمان حال فعل «بودن» گفته نمی‌شود: «Я студент» یعنی «من دانشجو هستم». «Это» به چیزی اشاره می‌کند و «у меня есть» یعنی «من دارم».","uk":"Називний відмінок — це початкова форма слова (хто? що?). У теперішньому часі дієслово «бути» не вимовляється: «Я студент». Словом «это» вказують на предмет, а «у меня есть» означає «я маю».","ar_sy":"حالة المبتدأ هي الشكل الأساسي للكلمة (مين؟ شو؟). بالمضارع فعل «كان» ما بينلفظ: «Я студент» يعني «أنا طالب». بـ«это» بتشير لشي، و«у меня есть» يعني «عندي»."},"tables":[{"caption":{"ru":"«Быть» опускается в настоящем времени","de":"«Sein» entfällt im Präsens","en":"“To be” is omitted in the present","fr":"« Être » est omis au présent","fa":"«بودن» در زمان حال حذف می‌شود","uk":"«Бути» опускається в теперішньому часі","ar_sy":"«كان» بينحذف بالمضارع"},"labelHeader":{"ru":"Лицо","de":"Person","en":"Person","fr":"Personne","fa":"شخص","uk":"Особа","ar_sy":"الضمير"},"columns":[{"ru":"Настоящее (без «быть»)","de":"Präsens (ohne «sein»)","en":"Present (no “to be”)","fr":"Présent (sans « être »)","fa":"زمان حال (بدون «بودن»)","uk":"Теперішній (без «бути»)","ar_sy":"المضارع (بدون «كان»)"},{"ru":"Прошедшее (был/была)","de":"Vergangenheit (war)","en":"Past (was)","fr":"Passé (était)","fa":"گذشته (بود)","uk":"Минулий (був/була)","ar_sy":"الماضي (كان/كانت)"}],"rows":[{"label":{"ru":"я (м.)","de":"ich (m.)","en":"I (m.)","fr":"je (m.)","fa":"من (مذکر)","uk":"я (ч.)","ar_sy":"أنا (مذكر)"},"cells":["Я студент","Я был студентом"]},{"label":{"ru":"она","de":"sie","en":"she","fr":"elle","fa":"او (مؤنث)","uk":"вона","ar_sy":"هي"},"cells":["Она врач","Она была врачом"]},{"label":{"ru":"они","de":"sie (Pl.)","en":"they","fr":"ils/elles","fa":"آنها","uk":"вони","ar_sy":"هنّ/هُم"},"cells":["Они друзья","Они были друзьями"]}]},{"caption":{"ru":"«Это» и «у меня есть»","de":"«Das ist» und «ich habe»","en":"“This is” and “I have”","fr":"« C'est » et « j'ai »","fa":"«این است» و «من دارم»","uk":"«Це» і «у мене є»","ar_sy":"«هادا» و«عندي»"},"labelHeader":{"ru":"Конструкция","de":"Konstruktion","en":"Construction","fr":"Construction","fa":"ساختار","uk":"Конструкція","ar_sy":"التركيب"},"columns":[{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"это = «это есть»","de":"это = «das ist»","en":"это = “this is”","fr":"это = « c'est »","fa":"это = «این است»","uk":"это = «це є»","ar_sy":"это = «هادا»"},"cells":["Это мой дом"]},{"label":{"ru":"у меня есть = «я имею»","de":"у меня есть = «ich habe»","en":"у меня есть = “I have”","fr":"у меня есть = « j'ai »","fa":"у меня есть = «من دارم»","uk":"у меня есть = «я маю»","ar_sy":"у меня есть = «عندي»"},"cells":["У меня есть брат"]}]}],"examples":[{"ru":"Меня зовут Анна, я преподаватель.","de":"Ich heiße Anna, ich bin Lehrerin.","en":"My name is Anna, I am a teacher.","fr":"Je m'appelle Anna, je suis enseignante.","fa":"اسم من آنا است، من معلم هستم.","uk":"Мене звати Анна, я викладачка.","ar_sy":"اسمي آنا، أنا مدرّسة."},{"ru":"Это Москва, а это Красная площадь.","de":"Das ist Moskau, und das ist der Rote Platz.","en":"This is Moscow, and this is Red Square.","fr":"C'est Moscou, et c'est la place Rouge.","fa":"این مسکو است و این میدان سرخ است.","uk":"Це Москва, а це Червона площа.","ar_sy":"هادا موسكو، وهادا الساحة الحمرا."},{"ru":"У меня есть собака и кошка.","de":"Ich habe einen Hund und eine Katze.","en":"I have a dog and a cat.","fr":"J'ai un chien et un chat.","fa":"من یک سگ و یک گربه دارم.","uk":"У мене є собака і кішка.","ar_sy":"عندي كلب وقطة."}],"hints":{"de":"Wenn du «быть» im Präsens weglassen willst, denk an einen Gedankenstrich zwischen zwei Substantiven in der Schrift: «Москва — столица».","en":"In writing, two nouns joined by omitted “to be” often take a dash: «Москва — столица» (Moscow is the capital).","fr":"À l'écrit, deux noms reliés par « être » omis prennent souvent un tiret : « Москва — столица » (Moscou est la capitale).","fa":"در نوشتار، دو اسم که با «بودنِ» حذف‌شده به هم می‌پیوندند اغلب با خط تیره می‌آیند: «Москва — столица».","uk":"На письмі два іменники, з'єднані пропущеним «бути», часто беруть тире: «Москва — столиця».","ar_sy":"بالكتابة، اسمين مربوطين بـ«كان» المحذوف غالبًا بينحطّ بيناتهن شرطة: «Москва — столица»."}},
{"id":"vinitelnyy-padezh","icon":"🎯","level":"A1","title":{"ru":"Винительный падеж — прямое дополнение","de":"Der Akkusativ — direktes Objekt","en":"The accusative case — direct object","fr":"L'accusatif — complément d'objet direct","fa":"حالت مفعولی — مفعول مستقیم","uk":"Знахідний відмінок — прямий додаток","ar_sy":"حالة المفعول — المفعول به المباشر"},"intro":{"ru":"Винительный падеж отвечает на вопросы «кого? что?» и обозначает прямое дополнение: «Я читаю книгу». У неодушевлённых предметов мужского рода форма как в именительном, а у одушевлённых — как в родительном.","de":"Der Akkusativ antwortet auf «wen? was?» und bezeichnet das direkte Objekt: «Я читаю книгу» (Ich lese ein Buch). Unbelebte Maskulina bleiben wie im Nominativ, belebte werden wie im Genitiv gebildet.","en":"The accusative answers “whom? what?” and marks the direct object: «Я читаю книгу» (I am reading a book). Inanimate masculine nouns keep the nominative form, animate ones look like the genitive.","fr":"L'accusatif répond à « qui ? quoi ? » et marque le complément d'objet direct : « Я читаю книгу » (Je lis un livre). Les masculins inanimés gardent la forme du nominatif, les animés prennent celle du génitif.","fa":"حالت مفعولی به «چه کسی را؟ چه چیزی را؟» پاسخ می‌دهد و مفعول مستقیم را نشان می‌دهد: «Я читаю книгу» (کتاب می‌خوانم). اسم‌های مذکرِ بی‌جان مثل حالت نهادی می‌مانند، جاندارها مثل حالت اضافی می‌شوند.","uk":"Знахідний відмінок відповідає на питання «кого? що?» і позначає прямий додаток: «Я читаю книгу». У неживих іменників чоловічого роду форма як у називному, у живих — як у родовому.","ar_sy":"حالة المفعول بتجاوب على «مين؟ شو؟» وبتدل على المفعول به: «Я читаю книгу» (عم اقرا كتاب). المذكر غير العاقل بيضل متل المبتدأ، والعاقل بيصير متل حالة الإضافة."},"tables":[{"caption":{"ru":"Окончания винительного падежа (единственное число)","de":"Akkusativ-Endungen (Singular)","en":"Accusative endings (singular)","fr":"Terminaisons de l'accusatif (singulier)","fa":"پایانه‌های حالت مفعولی (مفرد)","uk":"Закінчення знахідного відмінка (однина)","ar_sy":"نهايات حالة المفعول (المفرد)"},"labelHeader":{"ru":"Род / тип","de":"Genus / Typ","en":"Gender / type","fr":"Genre / type","fa":"جنس / نوع","uk":"Рід / тип","ar_sy":"الجنس / النوع"},"columns":[{"ru":"Именительный","de":"Nominativ","en":"Nominative","fr":"Nominatif","fa":"نهادی","uk":"Називний","ar_sy":"المبتدأ"},{"ru":"Винительный","de":"Akkusativ","en":"Accusative","fr":"Accusatif","fa":"مفعولی","uk":"Знахідний","ar_sy":"المفعول"}],"rows":[{"label":{"ru":"жен. род -а/-я","de":"Femininum -а/-я","en":"feminine -а/-я","fr":"féminin -а/-я","fa":"مؤنث -а/-я","uk":"жін. рід -а/-я","ar_sy":"مؤنث -а/-я"},"cells":["книга, неделя","книгу, неделю"]},{"label":{"ru":"муж. неодуш.","de":"Mask. unbelebt","en":"masc. inanimate","fr":"masc. inanimé","fa":"مذکر بی‌جان","uk":"чол. неживий","ar_sy":"مذكر غير عاقل"},"cells":["стол, дом","стол, дом"]},{"label":{"ru":"муж. одуш.","de":"Mask. belebt","en":"masc. animate","fr":"masc. animé","fa":"مذکر جاندار","uk":"чол. живий","ar_sy":"مذكر عاقل"},"cells":["брат, студент","брата, студента"]},{"label":{"ru":"ср. род / жен. -ь","de":"Neutrum / Fem. -ь","en":"neuter / fem. -ь","fr":"neutre / fém. -ь","fa":"خنثی / مؤنث -ь","uk":"сер. рід / жін. -ь","ar_sy":"محايد / مؤنث -ь"},"cells":["окно, дверь","окно, дверь"]}]}],"examples":[{"ru":"Я вижу большой дом и красивый парк.","de":"Ich sehe ein großes Haus und einen schönen Park.","en":"I see a big house and a beautiful park.","fr":"Je vois une grande maison et un beau parc.","fa":"من یک خانه‌ی بزرگ و یک پارک زیبا می‌بینم.","uk":"Я бачу великий будинок і гарний парк.","ar_sy":"أنا شايف بيت كبير وحديقة حلوة."},{"ru":"Мы ждём Ивана и Марию у входа.","de":"Wir warten am Eingang auf Iwan und Maria.","en":"We are waiting for Ivan and Maria at the entrance.","fr":"Nous attendons Ivan et Maria à l'entrée.","fa":"ما ایوان و ماریا را دم ورودی منتظریم.","uk":"Ми чекаємо Івана і Марію біля входу.","ar_sy":"عم نستنى إيفان وماريا عند الباب."},{"ru":"Каждое утро она пьёт кофе и читает газету.","de":"Jeden Morgen trinkt sie Kaffee und liest die Zeitung.","en":"Every morning she drinks coffee and reads the newspaper.","fr":"Chaque matin, elle boit du café et lit le journal.","fa":"او هر صبح قهوه می‌نوشد و روزنامه می‌خواند.","uk":"Щоранку вона п'є каву і читає газету.","ar_sy":"كل صبح بتشرب قهوة وبتقرا الجريدة."}],"hints":{"de":"Merke die «Belebtheitsregel»: Bei Menschen und Tieren (belebt, maskulin) ist der Akkusativ gleich dem Genitiv — «Я вижу брата», nicht «брат».","en":"Remember the animacy rule: for people and animals (animate masculine) the accusative equals the genitive — «Я вижу брата», not «брат».","fr":"Retiens la règle d'animation : pour les personnes et animaux (masculin animé), l'accusatif est égal au génitif — « Я вижу брата », pas « брат ».","fa":"قاعده‌ی جانداری را به یاد داشته باش: برای انسان‌ها و حیوانات (مذکر جاندار) حالت مفعولی برابر حالت اضافی است — «Я вижу брата»، نه «брат».","uk":"Запам'ятай правило істот: для людей і тварин (живий чоловічий рід) знахідний дорівнює родовому — «Я вижу брата», а не «брат».","ar_sy":"تذكّر قاعدة العاقل: مع الناس والحيوانات (مذكر عاقل) المفعول متل حالة الإضافة — «Я вижу брата»، مو «брат»."}},
{"id":"predlozhnyy-padezh","icon":"📍","level":"A1","title":{"ru":"Предложный падеж — место (в/на) и «о/об»","de":"Der Präpositiv — Ort (в/на) und «о/об»","en":"The prepositional case — location (в/на) and “о/об”","fr":"Le prépositionnel — lieu (в/на) et « о/об »","fa":"حالت حرف اضافه‌ای — مکان (в/на) و «о/об»","uk":"Місцевий відмінок — місце (в/на) і «о/об»","ar_sy":"حالة الجر — المكان (в/на) و«о/об»"},"intro":{"ru":"Предложный падеж всегда идёт с предлогом. После «в» и «на» он отвечает на вопрос «где?»: «в парке, на работе». После «о/об» он значит «о чём?»: «о книге». Типичное окончание — «-е».","de":"Der Präpositiv steht immer mit einer Präposition. Nach «в» und «на» beantwortet er «wo?»: «в парке, на работе». Nach «о/об» bedeutet er «worüber?»: «о книге». Die typische Endung ist «-е».","en":"The prepositional case always comes with a preposition. After «в» and «на» it answers “where?”: «в парке, на работе». After «о/об» it means “about what?”: «о книге». The typical ending is «-е».","fr":"Le prépositionnel s'emploie toujours avec une préposition. Après « в » et « на », il répond à « où ? » : « в парке, на работе ». Après « о/об », il signifie « à propos de quoi ? » : « о книге ». La terminaison type est « -е ».","fa":"حالت حرف اضافه‌ای همیشه با یک حرف اضافه می‌آید. بعد از «в» و «на» به «کجا؟» پاسخ می‌دهد: «в парке, на работе». بعد از «о/об» یعنی «درباره‌ی چه؟»: «о книге». پایانه‌ی معمول «-е» است.","uk":"Місцевий відмінок завжди йде з прийменником. Після «в» і «на» він відповідає на питання «де?»: «в парке, на работе». Після «о/об» означає «про що?»: «о книге». Типове закінчення — «-е».","ar_sy":"حالة الجر دايمًا بتجي مع حرف جر. بعد «в» و«на» بتجاوب على «وين؟»: «в парке, на работе». بعد «о/об» بتعني «عن شو؟»: «о книге». النهاية المعتادة «-е»."},"tables":[{"caption":{"ru":"«Где?» — в/на + предложный падеж","de":"«Wo?» — в/на + Präpositiv","en":"“Where?” — в/на + prepositional","fr":"« Où ? » — в/на + prépositionnel","fa":"«کجا؟» — в/на + حالت حرف اضافه‌ای","uk":"«Де?» — в/на + місцевий","ar_sy":"«وين؟» — в/на + حالة الجر"},"labelHeader":{"ru":"Именительный","de":"Nominativ","en":"Nominative","fr":"Nominatif","fa":"نهادی","uk":"Називний","ar_sy":"المبتدأ"},"columns":[{"ru":"Где? (предложный)","de":"Wo? (Präpositiv)","en":"Where? (prepositional)","fr":"Où ? (prépositionnel)","fa":"کجا؟ (حالت حرف اضافه‌ای)","uk":"Де? (місцевий)","ar_sy":"وين؟ (حالة الجر)"}],"rows":[{"label":{"ru":"парк","de":"Park","en":"park","fr":"parc","fa":"پارک","uk":"парк","ar_sy":"حديقة"},"cells":["в парке"]},{"label":{"ru":"работа","de":"Arbeit","en":"work","fr":"travail","fa":"کار","uk":"робота","ar_sy":"شغل"},"cells":["на работе"]},{"label":{"ru":"море","de":"Meer","en":"sea","fr":"mer","fa":"دریا","uk":"море","ar_sy":"بحر"},"cells":["на море"]},{"label":{"ru":"площадь (-ь)","de":"Platz (-ь)","en":"square (-ь)","fr":"place (-ь)","fa":"میدان (-ь)","uk":"площа (-ь)","ar_sy":"ساحة (-ь)"},"cells":["на площади"]}]},{"caption":{"ru":"«О чём?» — о или об","de":"«Worüber?» — о oder об","en":"“About what?” — о or об","fr":"« À propos de quoi ? » — о ou об","fa":"«درباره‌ی چه؟» — о یا об","uk":"«Про що?» — о чи об","ar_sy":"«عن شو؟» — о أو об"},"labelHeader":{"ru":"Правило","de":"Regel","en":"Rule","fr":"Règle","fa":"قاعده","uk":"Правило","ar_sy":"القاعدة"},"columns":[{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"о + согласный","de":"о + Konsonant","en":"о + consonant","fr":"о + consonne","fa":"о + همخوان","uk":"о + приголосний","ar_sy":"о + حرف ساكن"},"cells":["о книге, о доме"]},{"label":{"ru":"об + гласный (а,э,и,о,у)","de":"об + Vokal (а,э,и,о,у)","en":"об + vowel (а,э,и,о,у)","fr":"об + voyelle (а,э,и,о,у)","fa":"об + واکه (а,э,и,о,у)","uk":"об + голосний (а,э,и,о,у)","ar_sy":"об + حرف علة (а,э,и,о,у)"},"cells":["об Анне, об окне"]}]}],"examples":[{"ru":"Мои родители живут в маленьком городе.","de":"Meine Eltern wohnen in einer kleinen Stadt.","en":"My parents live in a small town.","fr":"Mes parents vivent dans une petite ville.","fa":"پدر و مادر من در یک شهر کوچک زندگی می‌کنند.","uk":"Мої батьки живуть у маленькому місті.","ar_sy":"أهلي عايشين بمدينة زغيرة."},{"ru":"Мы часто говорим о работе и о будущем.","de":"Wir sprechen oft über die Arbeit und über die Zukunft.","en":"We often talk about work and about the future.","fr":"Nous parlons souvent du travail et de l'avenir.","fa":"ما اغلب درباره‌ی کار و درباره‌ی آینده حرف می‌زنیم.","uk":"Ми часто говоримо про роботу і про майбутнє.","ar_sy":"منحكي كتير عن الشغل وعن المستقبل."},{"ru":"Книга лежит на столе, а ручка в сумке.","de":"Das Buch liegt auf dem Tisch und der Stift in der Tasche.","en":"The book is on the table, and the pen is in the bag.","fr":"Le livre est sur la table et le stylo dans le sac.","fa":"کتاب روی میز است و خودکار در کیف است.","uk":"Книга лежить на столі, а ручка в сумці.","ar_sy":"الكتاب عالطاولة، والقلم بالشنطة."}],"hints":{"de":"Faustregel: «в» = drinnen (в доме), «на» = auf Flächen und bei Ereignissen/Tätigkeiten (на работе, на концерте). Einige Wörter nehmen immer «на»: работа, вокзал, почта.","en":"Rule of thumb: «в» = inside (в доме), «на» = on surfaces and for events/activities (на работе, на концерте). A few words always take «на»: работа, вокзал, почта.","fr":"Règle générale : « в » = à l'intérieur (в доме), « на » = sur des surfaces et pour événements/activités (на работе, на концерте). Quelques mots prennent toujours « на » : работа, вокзал, почта.","fa":"قاعده‌ی کلی: «в» = داخل (в доме)، «на» = روی سطح‌ها و برای رویدادها/فعالیت‌ها (на работе، на концерте). چند واژه همیشه «на» می‌گیرند: работа، вокзал، почта.","uk":"Загальне правило: «в» = всередині (в доме), «на» = на поверхнях і для подій/занять (на работе, на концерте). Кілька слів завжди беруть «на»: работа, вокзал, почта.","ar_sy":"قاعدة عامة: «в» = جوّا (в доме)، «на» = عالأسطح ومع الأحداث/النشاطات (на работе، на концерте). كم كلمة دايمًا بياخدوا «на»: работа، вокзал، почта."}},
{"id":"mnozhestvennoe-chislo","icon":"➕","level":"A1","title":{"ru":"Множественное число (именительный)","de":"Der Plural (Nominativ)","en":"Noun plural (nominative)","fr":"Le pluriel des noms (nominatif)","fa":"جمع اسم‌ها (نهادی)","uk":"Множина іменників (називний)","ar_sy":"جمع الأسماء (المبتدأ)"},"intro":{"ru":"Чтобы образовать множественное число, к слову добавляют «-ы» или «-и». Мужской и женский род на согласный или -а/-я → «-ы/-и», средний род → «-а/-я». После к, г, х, ж, ш, ч, щ всегда пишем «-и».","de":"Für den Plural hängt man «-ы» oder «-и» an. Maskulinum/Femininum auf Konsonant oder -а/-я → «-ы/-и», Neutrum → «-а/-я». Nach к, г, х, ж, ш, ч, щ steht immer «-и».","en":"To form the plural you add «-ы» or «-и». Masculine/feminine ending in a consonant or -а/-я → «-ы/-и», neuter → «-а/-я». After к, г, х, ж, ш, ч, щ you always write «-и».","fr":"Pour le pluriel, on ajoute « -ы » ou « -и ». Masculin/féminin en consonne ou -а/-я → « -ы/-и », neutre → « -а/-я ». Après к, г, х, ж, ш, ч, щ on écrit toujours « -и ».","fa":"برای ساختن جمع «-ы» یا «-и» اضافه می‌شود. مذکر/مؤنثِ منتهی به همخوان یا -а/-я ← «-ы/-и»، خنثی ← «-а/-я». بعد از к، г، х، ж، ш، ч، щ همیشه «-и» می‌نویسیم.","uk":"Щоб утворити множину, до слова додають «-ы» або «-и». Чоловічий/жіночий рід на приголосний чи -а/-я → «-ы/-и», середній рід → «-а/-я». Після к, г, х, ж, ш, ч, щ завжди пишемо «-и».","ar_sy":"لتصريف الجمع بنضيف «-ы» أو «-и». المذكر/المؤنث اللي بينتهي بحرف ساكن أو -а/-я ← «-ы/-и»، المحايد ← «-а/-я». بعد к، г، х، ж، ш، ч، щ دايمًا بنكتب «-и»."},"tables":[{"caption":{"ru":"Регулярные окончания множественного числа","de":"Regelmäßige Plural-Endungen","en":"Regular plural endings","fr":"Terminaisons régulières du pluriel","fa":"پایانه‌های منظم جمع","uk":"Регулярні закінчення множини","ar_sy":"نهايات الجمع المنتظمة"},"labelHeader":{"ru":"Тип слова","de":"Worttyp","en":"Word type","fr":"Type de mot","fa":"نوع واژه","uk":"Тип слова","ar_sy":"نوع الكلمة"},"columns":[{"ru":"Единственное","de":"Singular","en":"Singular","fr":"Singulier","fa":"مفرد","uk":"Однина","ar_sy":"المفرد"},{"ru":"Множественное","de":"Plural","en":"Plural","fr":"Pluriel","fa":"جمع","uk":"Множина","ar_sy":"الجمع"}],"rows":[{"label":{"ru":"муж. + согласный → -ы","de":"Mask. + Konsonant → -ы","en":"masc. + consonant → -ы","fr":"masc. + consonne → -ы","fa":"مذکر + همخوان ← -ы","uk":"чол. + приголосний → -ы","ar_sy":"مذكر + ساكن ← -ы"},"cells":["стол","столы"]},{"label":{"ru":"жен. -а → -ы","de":"Fem. -а → -ы","en":"fem. -а → -ы","fr":"fém. -а → -ы","fa":"مؤنث -а ← -ы","uk":"жін. -а → -ы","ar_sy":"مؤنث -а ← -ы"},"cells":["книга","книги"]},{"label":{"ru":"после к,г,х,ж,ш,ч,щ → -и","de":"nach к,г,х,ж,ш,ч,щ → -и","en":"after к,г,х,ж,ш,ч,щ → -и","fr":"après к,г,х,ж,ш,ч,щ → -и","fa":"بعد از к,г,х,ж,ш,ч,щ ← -и","uk":"після к,г,х,ж,ш,ч,щ → -и","ar_sy":"بعد к,г,х,ж,ш,ч,щ ← -и"},"cells":["рука","руки"]},{"label":{"ru":"ср. -о → -а","de":"Neutr. -о → -а","en":"neut. -о → -а","fr":"neut. -о → -а","fa":"خنثی -о ← -а","uk":"сер. -о → -а","ar_sy":"محايد -о ← -а"},"cells":["окно","окна"]},{"label":{"ru":"ср. -е → -я","de":"Neutr. -е → -я","en":"neut. -е → -я","fr":"neut. -е → -я","fa":"خنثی -е ← -я","uk":"сер. -е → -я","ar_sy":"محايد -е ← -я"},"cells":["море","моря"]}]},{"caption":{"ru":"Частые нерегулярные формы","de":"Häufige unregelmäßige Formen","en":"Common irregular forms","fr":"Formes irrégulières fréquentes","fa":"شکل‌های بی‌قاعده‌ی پرکاربرد","uk":"Часті нерегулярні форми","ar_sy":"صيغ شاذة شائعة"},"labelHeader":{"ru":"Единственное","de":"Singular","en":"Singular","fr":"Singulier","fa":"مفرد","uk":"Однина","ar_sy":"المفرد"},"columns":[{"ru":"Множественное","de":"Plural","en":"Plural","fr":"Pluriel","fa":"جمع","uk":"Множина","ar_sy":"الجمع"}],"rows":[{"label":{"ru":"друг","de":"Freund","en":"friend","fr":"ami","fa":"دوست","uk":"друг","ar_sy":"صاحب"},"cells":["друзья"]},{"label":{"ru":"брат","de":"Bruder","en":"brother","fr":"frère","fa":"برادر","uk":"брат","ar_sy":"أخ"},"cells":["братья"]},{"label":{"ru":"ребёнок","de":"Kind","en":"child","fr":"enfant","fa":"کودک","uk":"дитина","ar_sy":"ولد"},"cells":["дети"]},{"label":{"ru":"человек","de":"Mensch","en":"person","fr":"personne","fa":"انسان","uk":"людина","ar_sy":"إنسان"},"cells":["люди"]},{"label":{"ru":"город","de":"Stadt","en":"city","fr":"ville","fa":"شهر","uk":"місто","ar_sy":"مدينة"},"cells":["города"]}]}],"examples":[{"ru":"В нашем городе есть парки, музеи и магазины.","de":"In unserer Stadt gibt es Parks, Museen und Geschäfte.","en":"In our city there are parks, museums and shops.","fr":"Dans notre ville, il y a des parcs, des musées et des magasins.","fa":"در شهر ما پارک‌ها، موزه‌ها و مغازه‌ها هست.","uk":"У нашому місті є парки, музеї та магазини.","ar_sy":"بمدينتنا في حدائق ومتاحف ومحلات."},{"ru":"Мои друзья и их дети приехали в гости.","de":"Meine Freunde und ihre Kinder sind zu Besuch gekommen.","en":"My friends and their children came to visit.","fr":"Mes amis et leurs enfants sont venus nous rendre visite.","fa":"دوستانم و بچه‌هایشان به دیدن ما آمدند.","uk":"Мої друзі та їхні діти приїхали в гості.","ar_sy":"أصحابي وولادهن إجوا يزورونا."},{"ru":"На столе лежат книги, ручки и телефоны.","de":"Auf dem Tisch liegen Bücher, Stifte und Telefone.","en":"On the table there are books, pens and phones.","fr":"Sur la table, il y a des livres, des stylos et des téléphones.","fa":"روی میز کتاب‌ها، خودکارها و تلفن‌ها هستند.","uk":"На столі лежать книги, ручки і телефони.","ar_sy":"عالطاولة في كتب وأقلام وتلفونات."}],"hints":{"de":"Vorsicht bei Maskulina mit Betonungswechsel und «-а»: город → города, дом → дома. Manche Wörter haben nur Plural (люди, дети) — lerne sie als Vokabel.","en":"Watch out for stressed masculines that take «-а»: город → города, дом → дома. A few words are plural-only (люди, дети) — memorize them as vocabulary.","fr":"Attention aux masculins accentués en « -а » : город → города, дом → дома. Quelques mots n'existent qu'au pluriel (люди, дети) — apprends-les par cœur.","fa":"مواظب مذکرهای تکیه‌دار با «-а» باش: город → города، дом → дома. چند واژه فقط جمع‌اند (люди، дети) — آنها را مثل واژه حفظ کن.","uk":"Увага до чоловічих іменників із наголошеним «-а»: город → города, дом → дома. Кілька слів мають лише множину (люди, дети) — вивчи їх напам'ять.","ar_sy":"دير بالك من المذكر اللي بياخد «-а»: город → города، дом → дома. كم كلمة بتجي بس جمع (люди، дети) — احفظهن متل مفردات."}},
{"id":"roditelnyy-padezh","icon":"🧲","level":"A2","title":{"ru":"Родительный падеж","de":"Genitiv","en":"Genitive case","fr":"Le génitif","fa":"حالت اضافه (مالکیت)","uk":"Родовий відмінок","ar_sy":"حالة المضاف (الملكية)"},"intro":{"ru":"Родительный падеж показывает принадлежность (у меня, дом брата), употребляется после «нет» и после чисел от пяти.","de":"Der Genitiv drückt Besitz aus (у меня, дом брата), steht nach «нет» (nicht vorhanden) und nach Zahlen ab fünf.","en":"The genitive shows possession (у меня, my brother's house), is used after «нет» (there isn't) and after numbers from five up.","fr":"Le génitif exprime la possession (у меня, la maison du frère), s'emploie après «нет» (il n'y a pas) et après les nombres à partir de cinq.","fa":"حالت اضافه مالکیت را نشان می‌دهد (у меня، خانه‌ی برادر)، بعد از «нет» (وجود ندارد) و بعد از اعداد از پنج به بالا می‌آید.","uk":"Родовий відмінок показує належність (у мене, дім брата), уживається після «нет» і після чисел від п'яти.","ar_sy":"حالة المضاف بتدل على الملكية (у меня، بيت الأخ)، وبتيجي بعد «нет» (ما في) وبعد الأرقام من خمسة وفوق."},"tables":[{"caption":{"ru":"Окончания родительного падежа (ед. ч.)","de":"Genitiv-Endungen (Singular)","en":"Genitive endings (singular)","fr":"Terminaisons du génitif (singulier)","fa":"پایانه‌های حالت اضافه (مفرد)","uk":"Закінчення родового відмінка (однина)","ar_sy":"نهايات حالة المضاف (مفرد)"},"labelHeader":{"ru":"Род / тип","de":"Genus / Typ","en":"Gender / type","fr":"Genre / type","fa":"جنس / نوع","uk":"Рід / тип","ar_sy":"الجنس / النوع"},"columns":[{"ru":"Именительный","de":"Nominativ","en":"Nominative","fr":"Nominatif","fa":"حالت فاعلی","uk":"Називний","ar_sy":"حالة الرفع"},{"ru":"Родительный","de":"Genitiv","en":"Genitive","fr":"Génitif","fa":"حالت اضافه","uk":"Родовий","ar_sy":"حالة المضاف"}],"rows":[{"label":{"ru":"муж. (твёрдый)","de":"Mask. (hart)","en":"masc. (hard)","fr":"masc. (dur)","fa":"مذکر (سخت)","uk":"чол. (твердий)","ar_sy":"مذكر (صلب)"},"cells":["стол","стола"]},{"label":{"ru":"муж. (мягкий)","de":"Mask. (weich)","en":"masc. (soft)","fr":"masc. (mou)","fa":"مذکر (نرم)","uk":"чол. (м'який)","ar_sy":"مذكر (لين)"},"cells":["музей","музея"]},{"label":{"ru":"жен. -а","de":"Fem. -а","en":"fem. -а","fr":"fém. -а","fa":"مؤنث -а","uk":"жін. -а","ar_sy":"مؤنث -а"},"cells":["вода","воды"]},{"label":{"ru":"жен. -я","de":"Fem. -я","en":"fem. -я","fr":"fém. -я","fa":"مؤنث -я","uk":"жін. -я","ar_sy":"مؤنث -я"},"cells":["неделя","недели"]},{"label":{"ru":"ср. -о","de":"Neutr. -о","en":"neut. -о","fr":"neutre -о","fa":"خنثی -о","uk":"сер. -о","ar_sy":"محايد -о"},"cells":["окно","окна"]}]},{"caption":{"ru":"Основные значения","de":"Wichtige Verwendungen","en":"Main uses","fr":"Emplois principaux","fa":"کاربردهای اصلی","uk":"Основні вживання","ar_sy":"الاستعمالات الأساسية"},"labelHeader":{"ru":"Значение","de":"Bedeutung","en":"Use","fr":"Emploi","fa":"کاربرد","uk":"Уживання","ar_sy":"الاستعمال"},"columns":[{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"принадлежность (у + род.)","de":"Besitz (у + Gen.)","en":"possession (у + gen.)","fr":"possession (у + gén.)","fa":"مالکیت (у + اضافه)","uk":"належність (у + род.)","ar_sy":"ملكية (у + مضاف)"},"cells":["У сестры есть кот"]},{"label":{"ru":"отрицание (нет + род.)","de":"Verneinung (нет + Gen.)","en":"negation (нет + gen.)","fr":"négation (нет + gén.)","fa":"نفی (нет + اضافه)","uk":"заперечення (нет + род.)","ar_sy":"نفي (нет + مضاف)"},"cells":["Здесь нет молока"]},{"label":{"ru":"количество / после чисел","de":"Menge / nach Zahlen","en":"quantity / after numbers","fr":"quantité / après les nombres","fa":"مقدار / بعد از اعداد","uk":"кількість / після чисел","ar_sy":"كمية / بعد الأرقام"},"cells":["шесть студентов"]}]}],"examples":[{"ru":"У меня нет времени.","de":"Ich habe keine Zeit.","en":"I don't have time.","fr":"Je n'ai pas le temps.","fa":"من وقت ندارم.","uk":"У мене немає часу.","ar_sy":"ما عندي وقت."},{"ru":"Это дом моего брата.","de":"Das ist das Haus meines Bruders.","en":"This is my brother's house.","fr":"C'est la maison de mon frère.","fa":"این خانه‌ی برادرم است.","uk":"Це дім мого брата.","ar_sy":"هادا بيت أخوي."},{"ru":"Я купил килограмм яблок.","de":"Ich habe ein Kilogramm Äpfel gekauft.","en":"I bought a kilogram of apples.","fr":"J'ai acheté un kilo de pommes.","fa":"یک کیلو سیب خریدم.","uk":"Я купив кілограм яблук.","ar_sy":"اشتريت كيلو تفاح."}],"hints":{"de":"Nach нет und у steht immer der Genitiv. Zahlen ab 5 verlangen den Genitiv Plural (пять книг).","en":"After нет and у always use the genitive. Numbers from 5 up take the genitive plural (пять книг).","fr":"Après нет et у, employez toujours le génitif. Les nombres à partir de 5 exigent le génitif pluriel (пять книг).","fa":"بعد از нет و у همیشه حالت اضافه به کار می‌رود. اعداد از ۵ به بالا جمعِ اضافه می‌گیرند (пять книг).","uk":"Після нет і у завжди вживай родовий відмінок. Числа від 5 вимагають родового множини (пять книг).","ar_sy":"بعد نет و у دايماً بتستعمل حالة المضاف. الأرقام من 5 وفوق بدها الجمع بحالة المضاف (пять книг)."}},
{"id":"datelnyy-padezh","icon":"🎁","level":"A2","title":{"ru":"Дательный падеж","de":"Dativ","en":"Dative case","fr":"Le datif","fa":"حالت مفعول غیرمستقیم","uk":"Давальний відмінок","ar_sy":"حالة المفعول غير المباشر"},"intro":{"ru":"Дательный падеж обозначает адресата действия (кому?), используется для возраста (мне двадцать лет), с глаголом «нравиться» и словами «надо», «нужно».","de":"Der Dativ bezeichnet den Empfänger der Handlung (кому? – wem?), dient zur Altersangabe (мне двадцать лет), steht bei «нравиться» und bei «надо», «нужно».","en":"The dative marks the recipient of an action (кому? – to whom?), is used for age (мне двадцать лет), with the verb «нравиться» (to like) and with «надо», «нужно» (need).","fr":"Le datif marque le destinataire de l'action (кому? – à qui ?), sert à indiquer l'âge (мне двадцать лет), s'emploie avec «нравиться» (plaire) et «надо», «нужно» (il faut).","fa":"حالت مفعول غیرمستقیم گیرنده‌ی کنش را نشان می‌دهد (кому؟ – به چه کسی؟)، برای بیان سن به کار می‌رود (мне двадцать лет)، و با فعل «нравиться» و واژه‌های «надо»، «нужно» می‌آید.","uk":"Давальний відмінок позначає адресата дії (кому?), уживається для віку (мне двадцать лет), з дієсловом «нравиться» та словами «надо», «нужно».","ar_sy":"حالة المفعول غير المباشر بتدل على مين وصل له الفعل (кому؟ – لمين؟)، وبتستعمل للعمر (мне двадцать лет)، ومع الفعل «нравиться» وكلمات «надо»، «нужно»."},"tables":[{"caption":{"ru":"Окончания дательного падежа (ед. ч.)","de":"Dativ-Endungen (Singular)","en":"Dative endings (singular)","fr":"Terminaisons du datif (singulier)","fa":"پایانه‌های حالت مفعول غیرمستقیم (مفرد)","uk":"Закінчення давального відмінка (однина)","ar_sy":"نهايات حالة المفعول غير المباشر (مفرد)"},"labelHeader":{"ru":"Род / тип","de":"Genus / Typ","en":"Gender / type","fr":"Genre / type","fa":"جنس / نوع","uk":"Рід / тип","ar_sy":"الجنس / النوع"},"columns":[{"ru":"Именительный","de":"Nominativ","en":"Nominative","fr":"Nominatif","fa":"حالت فاعلی","uk":"Називний","ar_sy":"حالة الرفع"},{"ru":"Дательный","de":"Dativ","en":"Dative","fr":"Datif","fa":"حالت مفعول غیرمستقیم","uk":"Давальний","ar_sy":"حالة المفعول غير المباشر"}],"rows":[{"label":{"ru":"муж. (твёрдый)","de":"Mask. (hart)","en":"masc. (hard)","fr":"masc. (dur)","fa":"مذکر (سخت)","uk":"чол. (твердий)","ar_sy":"مذكر (صلب)"},"cells":["брат","брату"]},{"label":{"ru":"муж. (мягкий)","de":"Mask. (weich)","en":"masc. (soft)","fr":"masc. (mou)","fa":"مذکر (نرم)","uk":"чол. (м'який)","ar_sy":"مذكر (لين)"},"cells":["учитель","учителю"]},{"label":{"ru":"жен. -а","de":"Fem. -а","en":"fem. -а","fr":"fém. -а","fa":"مؤنث -а","uk":"жін. -а","ar_sy":"مؤنث -а"},"cells":["сестра","сестре"]},{"label":{"ru":"ср. -о","de":"Neutr. -о","en":"neut. -о","fr":"neutre -о","fa":"خنثی -о","uk":"сер. -о","ar_sy":"محايد -о"},"cells":["окно","окну"]},{"label":{"ru":"местоимение (я)","de":"Pronomen (я)","en":"pronoun (я)","fr":"pronom (я)","fa":"ضمیر (я)","uk":"займенник (я)","ar_sy":"ضمير (я)"},"cells":["я","мне"]}]},{"caption":{"ru":"Основные значения","de":"Wichtige Verwendungen","en":"Main uses","fr":"Emplois principaux","fa":"کاربردهای اصلی","uk":"Основні вживання","ar_sy":"الاستعمالات الأساسية"},"labelHeader":{"ru":"Значение","de":"Bedeutung","en":"Use","fr":"Emploi","fa":"کاربرد","uk":"Уживання","ar_sy":"الاستعمال"},"columns":[{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"адресат (кому?)","de":"Empfänger (кому?)","en":"recipient (кому?)","fr":"destinataire (кому?)","fa":"گیرنده (кому؟)","uk":"адресат (кому?)","ar_sy":"المُرسَل إليه (кому؟)"},"cells":["Я пишу другу"]},{"label":{"ru":"возраст","de":"Alter","en":"age","fr":"âge","fa":"سن","uk":"вік","ar_sy":"العمر"},"cells":["Мне двадцать лет"]},{"label":{"ru":"нравиться","de":"gefallen (нравиться)","en":"to like (нравиться)","fr":"plaire (нравиться)","fa":"خوش آمدن (нравиться)","uk":"подобатися (нравиться)","ar_sy":"يعجب (нравиться)"},"cells":["Мне нравится Москва"]},{"label":{"ru":"надо / нужно","de":"müssen/brauchen (надо/нужно)","en":"need (надо/нужно)","fr":"il faut (надо/нужно)","fa":"لازم بودن (надо/нужно)","uk":"треба/потрібно (надо/нужно)","ar_sy":"لازم (надо/нужно)"},"cells":["Мне надо работать"]}]}],"examples":[{"ru":"Мне двадцать лет.","de":"Ich bin zwanzig Jahre alt.","en":"I am twenty years old.","fr":"J'ai vingt ans.","fa":"من بیست سالمه.","uk":"Мені двадцять років.","ar_sy":"عمري عشرين سنة."},{"ru":"Ей нравится этот город.","de":"Ihr gefällt diese Stadt.","en":"She likes this city.","fr":"Elle aime cette ville.","fa":"او این شهر را دوست دارد.","uk":"Їй подобається це місто.","ar_sy":"بيعجبها هالمدينة."},{"ru":"Нам нужно купить билеты.","de":"Wir müssen Fahrkarten kaufen.","en":"We need to buy tickets.","fr":"Nous devons acheter des billets.","fa":"ما باید بلیط بخریم.","uk":"Нам потрібно купити квитки.","ar_sy":"لازم نشتري تذاكر."}],"hints":{"de":"Beim Alter steht die Person im Dativ: мне … Jahre. Bei «нравиться» ist das, was gefällt, das grammatische Subjekt: Мне нравится книга.","en":"For age the person is in the dative: мне … years. With «нравиться» the thing liked is the grammatical subject: Мне нравится книга.","fr":"Pour l'âge, la personne est au datif : мне … ans. Avec «нравиться», ce qui plaît est le sujet grammatical : Мне нравится книга.","fa":"برای بیان سن، شخص در حالت مفعول غیرمستقیم می‌آید: мне … سال. با «нравиться»، چیزی که خوش می‌آید فاعل دستوری است: Мне нравится книга.","uk":"Для віку особа стоїть у давальному: мне … років. З «нравиться» те, що подобається, є граматичним підметом: Мне нравится книга.","ar_sy":"لعمر الشخص بيجي بحالة المفعول غير المباشر: мне … سنة. مع «нравиться» الشي يلي بيعجبك بيكون هو الفاعل النحوي: Мне нравится книга."}},
{"id":"tvoritelnyy-padezh","icon":"🔧","level":"A2","title":{"ru":"Творительный падеж","de":"Instrumental","en":"Instrumental case","fr":"L'instrumental","fa":"حالت وسیله (بایی)","uk":"Орудний відмінок","ar_sy":"حالة الأداة (المعية والوسيلة)"},"intro":{"ru":"Творительный падеж отвечает на вопрос «кем? чем?»: указывает орудие/средство, спутника (с кем), а также профессию с глаголом «быть» (быть врачом).","de":"Der Instrumental antwortet auf «кем? чем?» (womit? mit wem?): er bezeichnet Werkzeug/Mittel, den Begleiter (с кем) sowie den Beruf mit «быть» (быть врачом – Arzt sein).","en":"The instrumental answers «кем? чем?» (with whom? with what?): it marks the tool/means, the companion (с кем – with whom) and the profession with «быть» (быть врачом – to be a doctor).","fr":"L'instrumental répond à «кем? чем?» (avec qui ? avec quoi ?) : il marque l'outil/le moyen, le compagnon (с кем) ainsi que la profession avec «быть» (быть врачом – être médecin).","fa":"حالت وسیله به پرسش «кем? чем?» پاسخ می‌دهد (با چه کسی؟ با چه چیزی؟): ابزار/وسیله، همراه (с кем) و نیز شغل با فعل «быть» را نشان می‌دهد (быть врачом – پزشک بودن).","uk":"Орудний відмінок відповідає на «кем? чем?» (ким? чим?): позначає знаряддя/засіб, супутника (с кем) та професію з дієсловом «быть» (быть врачом).","ar_sy":"حالة الأداة بتجاوب على «кем? чем?» (مع مين؟ بشو؟): بتدل على الأداة/الوسيلة، والرفيق (с кем)، وكمان المهنة مع الفعل «быть» (быть врачом – يكون دكتور)."},"tables":[{"caption":{"ru":"Окончания творительного падежа (ед. ч.)","de":"Instrumental-Endungen (Singular)","en":"Instrumental endings (singular)","fr":"Terminaisons de l'instrumental (singulier)","fa":"پایانه‌های حالت وسیله (مفرد)","uk":"Закінчення орудного відмінка (однина)","ar_sy":"نهايات حالة الأداة (مفرد)"},"labelHeader":{"ru":"Род / тип","de":"Genus / Typ","en":"Gender / type","fr":"Genre / type","fa":"جنس / نوع","uk":"Рід / тип","ar_sy":"الجنس / النوع"},"columns":[{"ru":"Именительный","de":"Nominativ","en":"Nominative","fr":"Nominatif","fa":"حالت فاعلی","uk":"Називний","ar_sy":"حالة الرفع"},{"ru":"Творительный","de":"Instrumental","en":"Instrumental","fr":"Instrumental","fa":"حالت وسیله","uk":"Орудний","ar_sy":"حالة الأداة"}],"rows":[{"label":{"ru":"муж. (твёрдый)","de":"Mask. (hart)","en":"masc. (hard)","fr":"masc. (dur)","fa":"مذکر (سخت)","uk":"чол. (твердий)","ar_sy":"مذكر (صلب)"},"cells":["стол","столом"]},{"label":{"ru":"муж. (мягкий)","de":"Mask. (weich)","en":"masc. (soft)","fr":"masc. (mou)","fa":"مذکر (نرم)","uk":"чол. (м'який)","ar_sy":"مذكر (لين)"},"cells":["учитель","учителем"]},{"label":{"ru":"жен. -а","de":"Fem. -а","en":"fem. -а","fr":"fém. -а","fa":"مؤنث -а","uk":"жін. -а","ar_sy":"مؤنث -а"},"cells":["вода","водой"]},{"label":{"ru":"жен. -я","de":"Fem. -я","en":"fem. -я","fr":"fém. -я","fa":"مؤنث -я","uk":"жін. -я","ar_sy":"مؤنث -я"},"cells":["неделя","неделей"]},{"label":{"ru":"ср. -о","de":"Neutr. -о","en":"neut. -о","fr":"neutre -о","fa":"خنثی -о","uk":"сер. -о","ar_sy":"محايد -о"},"cells":["окно","окном"]}]},{"caption":{"ru":"Основные значения","de":"Wichtige Verwendungen","en":"Main uses","fr":"Emplois principaux","fa":"کاربردهای اصلی","uk":"Основні вживання","ar_sy":"الاستعمالات الأساسية"},"labelHeader":{"ru":"Значение","de":"Bedeutung","en":"Use","fr":"Emploi","fa":"کاربرد","uk":"Уживання","ar_sy":"الاستعمال"},"columns":[{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"орудие / средство (чем?)","de":"Werkzeug/Mittel (чем?)","en":"tool/means (чем?)","fr":"outil/moyen (чем?)","fa":"ابزار/وسیله (чем؟)","uk":"знаряддя/засіб (чем?)","ar_sy":"أداة/وسيلة (чем؟)"},"cells":["Я пишу ручкой"]},{"label":{"ru":"спутник (с + твор.)","de":"Begleiter (с + Instr.)","en":"companion (с + instr.)","fr":"compagnon (с + instr.)","fa":"همراه (с + وسیله)","uk":"супутник (с + оруд.)","ar_sy":"رفيق (с + أداة)"},"cells":["Я говорю с другом"]},{"label":{"ru":"профессия (быть + твор.)","de":"Beruf (быть + Instr.)","en":"profession (быть + instr.)","fr":"profession (быть + instr.)","fa":"شغل (быть + وسیله)","uk":"професія (быть + оруд.)","ar_sy":"مهنة (быть + أداة)"},"cells":["Он хочет быть врачом"]}]}],"examples":[{"ru":"Я ем суп ложкой.","de":"Ich esse Suppe mit dem Löffel.","en":"I eat soup with a spoon.","fr":"Je mange la soupe avec une cuillère.","fa":"من سوپ را با قاشق می‌خورم.","uk":"Я їм суп ложкою.","ar_sy":"بوكل الشوربة بالملعقة."},{"ru":"Мы гуляем с собакой.","de":"Wir gehen mit dem Hund spazieren.","en":"We are walking with the dog.","fr":"Nous nous promenons avec le chien.","fa":"ما با سگ قدم می‌زنیم.","uk":"Ми гуляємо з собакою.","ar_sy":"عم نتمشى مع الكلب."},{"ru":"Она работает учителем.","de":"Sie arbeitet als Lehrerin.","en":"She works as a teacher.","fr":"Elle travaille comme enseignante.","fa":"او به عنوان معلم کار می‌کند.","uk":"Вона працює вчителькою.","ar_sy":"هي بتشتغل معلمة."}],"hints":{"de":"«с» + Instrumental heißt «zusammen mit». Beruf und Zustand stehen im Instrumental: работать/быть/стать + Instrumental.","en":"«с» + instrumental means «together with». Profession and state take the instrumental: работать/быть/стать + instrumental.","fr":"«с» + instrumental signifie « avec (ensemble) ». La profession et l'état se mettent à l'instrumental : работать/быть/стать + instrumental.","fa":"«с» + حالت وسیله یعنی «همراه با». شغل و وضعیت با حالت وسیله می‌آیند: работать/быть/стать + حالت وسیله.","uk":"«с» + орудний означає «разом із». Професія і стан стоять в орудному: работать/быть/стать + орудний.","ar_sy":"«с» + حالة الأداة يعني «مع/سوا». المهنة والحالة بتيجي بحالة الأداة: работать/быть/стать + حالة الأداة."}},
{"id":"proshedshee-vremya","icon":"📅","level":"A2","title":{"ru":"Прошедшее время","de":"Vergangenheit (Präteritum)","en":"Past tense","fr":"Le passé","fa":"زمان گذشته","uk":"Минулий час","ar_sy":"الزمن الماضي"},"intro":{"ru":"Прошедшее время образуется от основы инфинитива с суффиксом -л и окончанием, которое согласуется с родом и числом подлежащего: -л (м.р.), -ла (ж.р.), -ло (ср.р.), -ли (мн.ч.).","de":"Die Vergangenheit wird vom Infinitivstamm mit dem Suffix -л gebildet; die Endung richtet sich nach Genus und Numerus des Subjekts: -л (m.), -ла (f.), -ло (n.), -ли (Pl.).","en":"The past tense is formed from the infinitive stem with the suffix -л; the ending agrees with the gender and number of the subject: -л (masc.), -ла (fem.), -ло (neut.), -ли (plural).","fr":"Le passé se forme sur le radical de l'infinitif avec le suffixe -л ; la terminaison s'accorde en genre et en nombre avec le sujet : -л (masc.), -ла (fém.), -ло (neutre), -ли (pluriel).","fa":"زمان گذشته از ریشه‌ی مصدر با پسوند -л ساخته می‌شود؛ پایانه با جنس و شمار فاعل مطابقت می‌کند: -л (مذکر)، -ла (مؤنث)، -ло (خنثی)، -ли (جمع).","uk":"Минулий час утворюється від основи інфінітива із суфіксом -л; закінчення узгоджується з родом і числом підмета: -л (ч.р.), -ла (ж.р.), -ло (с.р.), -ли (мн.).","ar_sy":"الزمن الماضي بينعمل من جذر المصدر مع اللاحقة -л؛ والنهاية بتتطابق مع جنس وعدد الفاعل: -л (مذكر)، -ла (مؤنث)، -ло (محايد)، -ли (جمع)."},"tables":[{"caption":{"ru":"Прошедшее время глагола «читать»","de":"Vergangenheit des Verbs «читать»","en":"Past tense of the verb «читать»","fr":"Passé du verbe «читать»","fa":"زمان گذشته‌ی فعل «читать»","uk":"Минулий час дієслова «читать»","ar_sy":"الماضي للفعل «читать»"},"labelHeader":{"ru":"Род / число","de":"Genus / Numerus","en":"Gender / number","fr":"Genre / nombre","fa":"جنس / شمار","uk":"Рід / число","ar_sy":"الجنس / العدد"},"columns":[{"ru":"Окончание","de":"Endung","en":"Ending","fr":"Terminaison","fa":"پایانه","uk":"Закінчення","ar_sy":"النهاية"},{"ru":"Форма","de":"Form","en":"Form","fr":"Forme","fa":"صورت","uk":"Форма","ar_sy":"الصيغة"}],"rows":[{"label":{"ru":"мужской род (он)","de":"maskulin (он)","en":"masculine (он)","fr":"masculin (он)","fa":"مذکر (он)","uk":"чоловічий (он)","ar_sy":"مذكر (он)"},"cells":["-л","читал"]},{"label":{"ru":"женский род (она)","de":"feminin (она)","en":"feminine (она)","fr":"féminin (она)","fa":"مؤنث (она)","uk":"жіночий (она)","ar_sy":"مؤنث (она)"},"cells":["-ла","читала"]},{"label":{"ru":"средний род (оно)","de":"neutrum (оно)","en":"neuter (оно)","fr":"neutre (оно)","fa":"خنثی (оно)","uk":"середній (оно)","ar_sy":"محايد (оно)"},"cells":["-ло","читало"]},{"label":{"ru":"множ. число (они)","de":"Plural (они)","en":"plural (они)","fr":"pluriel (они)","fa":"جمع (они)","uk":"множина (они)","ar_sy":"جمع (они)"},"cells":["-ли","читали"]}]},{"caption":{"ru":"Согласование по роду и числу","de":"Kongruenz nach Genus und Numerus","en":"Agreement by gender and number","fr":"Accord en genre et en nombre","fa":"مطابقت بر پایه‌ی جنس و شمار","uk":"Узгодження за родом і числом","ar_sy":"المطابقة بالجنس والعدد"},"labelHeader":{"ru":"Подлежащее","de":"Subjekt","en":"Subject","fr":"Sujet","fa":"فاعل","uk":"Підмет","ar_sy":"الفاعل"},"columns":[{"ru":"работать","de":"работать (Vergangenheit)","en":"работать (past)","fr":"работать (passé)","fa":"работать (گذشته)","uk":"работать (минулий)","ar_sy":"работать (ماضي)"},{"ru":"быть","de":"быть (Vergangenheit)","en":"быть (past)","fr":"быть (passé)","fa":"быть (گذشته)","uk":"быть (минулий)","ar_sy":"быть (ماضي)"}],"rows":[{"label":{"ru":"он","de":"он","en":"он","fr":"он","fa":"он","uk":"он","ar_sy":"он"},"cells":["работал","был"]},{"label":{"ru":"она","de":"она","en":"она","fr":"она","fa":"она","uk":"она","ar_sy":"она"},"cells":["работала","была"]},{"label":{"ru":"оно","de":"оно","en":"оно","fr":"оно","fa":"оно","uk":"оно","ar_sy":"оно"},"cells":["работало","было"]},{"label":{"ru":"они","de":"они","en":"они","fr":"они","fa":"они","uk":"они","ar_sy":"они"},"cells":["работали","были"]}]}],"examples":[{"ru":"Вчера я читал книгу.","de":"Gestern habe ich ein Buch gelesen.","en":"Yesterday I read a book.","fr":"Hier, j'ai lu un livre.","fa":"دیروز یک کتاب خواندم.","uk":"Учора я читав книгу.","ar_sy":"مبارح قريت كتاب."},{"ru":"Она была дома.","de":"Sie war zu Hause.","en":"She was at home.","fr":"Elle était à la maison.","fa":"او خانه بود.","uk":"Вона була вдома.","ar_sy":"هي كانت بالبيت."},{"ru":"Мы жили в Москве.","de":"Wir wohnten in Moskau.","en":"We lived in Moscow.","fr":"Nous vivions à Moscou.","fa":"ما در مسکو زندگی می‌کردیم.","uk":"Ми жили в Москві.","ar_sy":"نحنا عشنا بموسكو."}],"hints":{"de":"Im Präteritum spielt die Person keine Rolle – nur Genus und Numerus zählen: я читал (m.) / я читала (f.). Das -л entfällt im Maskulin mancher Verben (нёс, мог).","en":"In the past tense the person doesn't matter – only gender and number count: я читал (m.) / я читала (f.). The -л drops in the masculine of some verbs (нёс, мог).","fr":"Au passé, la personne n'a pas d'importance – seuls le genre et le nombre comptent : я читал (m.) / я читала (f.). Le -л disparaît au masculin de certains verbes (нёс, мог).","fa":"در زمان گذشته شخص مهم نیست – فقط جنس و شمار مهم است: я читал (مذکر) / я читала (مؤنث). پسوند -л در مذکرِ برخی افعال حذف می‌شود (нёс، мог).","uk":"У минулому часі особа не має значення – важливі лише рід і число: я читал (ч.) / я читала (ж.). Суфікс -л зникає в чоловічому роді деяких дієслів (нёс, мог).","ar_sy":"بالماضي الشخص ما بيفرق – بس الجنس والعدد يلي بيفرقوا: я читал (مذكر) / я читала (مؤنث). اللاحقة -л بتوقع بالمذكر بكم فعل (нёс، мог)."}},
{"id":"vid-glagola","icon":"🔄","level":"A2","title":{"ru":"Вид глагола: несовершенный и совершенный","de":"Verbalaspekt: unvollendet und vollendet","en":"Verbal aspect: imperfective and perfective","fr":"L'aspect verbal : imperfectif et perfectif","fa":"نمود فعل: ناتمام و کامل","uk":"Вид дієслова: недоконаний і доконаний","ar_sy":"نوع الفعل: الناقص والتام"},"intro":{"ru":"Почти каждый русский глагол существует в паре: несовершенный вид описывает процесс, повторение или длительность (что делать?), а совершенный вид — законченное действие с результатом (что сделать?). Выбор вида — самая важная особенность русского глагола.","de":"Fast jedes russische Verb existiert als Paar: Der unvollendete Aspekt beschreibt einen Prozess, eine Wiederholung oder Dauer (что делать?), der vollendete Aspekt eine abgeschlossene Handlung mit Ergebnis (что сделать?). Die Aspektwahl ist das wichtigste Merkmal des russischen Verbs.","en":"Almost every Russian verb comes as a pair: the imperfective describes a process, repetition or duration (что делать?), while the perfective describes a completed action with a result (что сделать?). Choosing the aspect is the most important feature of the Russian verb.","fr":"Presque chaque verbe russe existe par paire : l'imperfectif décrit un processus, une répétition ou une durée (что делать?), tandis que le perfectif décrit une action achevée avec un résultat (что сделать?). Le choix de l'aspect est la caractéristique la plus importante du verbe russe.","fa":"تقریباً هر فعل روسی به‌صورت جفتی وجود دارد: نمود ناتمام روند، تکرار یا استمرار را توصیف می‌کند (что делать؟)، و نمود کامل کنشی پایان‌یافته با نتیجه را (что сделать؟). انتخاب نمود مهم‌ترین ویژگی فعل روسی است.","uk":"Майже кожне російське дієслово існує в парі: недоконаний вид описує процес, повторення чи тривалість (что делать?), а доконаний — завершену дію з результатом (что сделать?). Вибір виду — найважливіша особливість російського дієслова.","ar_sy":"كل فعل روسي تقريباً بيجي بزوج: الناقص بيوصف عملية أو تكرار أو مدة (что делать؟)، والتام بيوصف فعل خلص وإله نتيجة (что сделать؟). اختيار النوع هو أهم شي بالفعل الروسي."},"tables":[{"caption":{"ru":"Видовые пары глаголов","de":"Aspektpaare der Verben","en":"Aspect pairs of verbs","fr":"Paires aspectuelles de verbes","fa":"جفت‌های نمودی افعال","uk":"Видові пари дієслів","ar_sy":"أزواج الأفعال حسب النوع"},"labelHeader":{"ru":"Значение","de":"Bedeutung","en":"Meaning","fr":"Sens","fa":"معنی","uk":"Значення","ar_sy":"المعنى"},"columns":[{"ru":"Несовершенный","de":"Unvollendet","en":"Imperfective","fr":"Imperfectif","fa":"ناتمام","uk":"Недоконаний","ar_sy":"الناقص"},{"ru":"Совершенный","de":"Vollendet","en":"Perfective","fr":"Perfectif","fa":"کامل","uk":"Доконаний","ar_sy":"التام"}],"rows":[{"label":{"ru":"делать","de":"machen","en":"to do","fr":"faire","fa":"انجام دادن","uk":"робити","ar_sy":"يعمل"},"cells":["делать","сделать"]},{"label":{"ru":"читать","de":"lesen","en":"to read","fr":"lire","fa":"خواندن","uk":"читати","ar_sy":"يقرأ"},"cells":["читать","прочитать"]},{"label":{"ru":"писать","de":"schreiben","en":"to write","fr":"écrire","fa":"نوشتن","uk":"писати","ar_sy":"يكتب"},"cells":["писать","написать"]},{"label":{"ru":"покупать","de":"kaufen","en":"to buy","fr":"acheter","fa":"خریدن","uk":"купувати","ar_sy":"يشتري"},"cells":["покупать","купить"]},{"label":{"ru":"брать","de":"nehmen","en":"to take","fr":"prendre","fa":"گرفتن","uk":"брати","ar_sy":"ياخذ"},"cells":["брать","взять"]}]}],"examples":[{"ru":"Я вчера читал книгу весь вечер. — процесс, без результата","de":"Ich habe gestern den ganzen Abend ein Buch gelesen. — Prozess, ohne Ergebnis","en":"Yesterday I read a book all evening. — process, no result","fr":"Hier, j'ai lu un livre toute la soirée. — processus, sans résultat","fa":"دیروز تمام عصر کتاب می‌خواندم. — روند، بدون نتیجه","uk":"Я вчора читав книжку весь вечір. — процес, без результату","ar_sy":"مبارح ضليت أقرا كتاب طول المسا. — عملية، بدون نتيجة"},{"ru":"Я прочитал книгу и вернул её в библиотеку. — результат достигнут","de":"Ich habe das Buch gelesen und in die Bibliothek zurückgebracht. — Ergebnis erreicht","en":"I read the book (finished it) and returned it to the library. — result achieved","fr":"J'ai lu le livre (fini) et l'ai rendu à la bibliothèque. — résultat atteint","fa":"کتاب را تمام خواندم و به کتابخانه برگرداندم. — نتیجه حاصل شد","uk":"Я прочитав книжку й повернув її до бібліотеки. — результат досягнуто","ar_sy":"خلّصت الكتاب ورجّعتو عالمكتبة. — وصلت النتيجة"},{"ru":"Каждое утро я покупаю хлеб, а сегодня купил ещё и молоко.","de":"Jeden Morgen kaufe ich Brot, und heute habe ich auch Milch gekauft.","en":"Every morning I buy bread, and today I also bought milk.","fr":"Chaque matin j'achète du pain, et aujourd'hui j'ai aussi acheté du lait.","fa":"هر صبح نان می‌خرم، و امروز شیر هم خریدم.","uk":"Щоранку я купую хліб, а сьогодні купив ще й молоко.","ar_sy":"كل صبح بشتري خبز، واليوم اشتريت كمان حليب."}],"hints":{"de":"Frage «что делать?» → unvollendet; «что сделать?» → vollendet. Ein einmaliges Ergebnis, ein Präfix (про-, на-, с-) signalisiert oft den vollendeten Aspekt.","en":"Ask «что делать?» → imperfective; «что сделать?» → perfective. A single result, or a prefix (про-, на-, с-) often signals the perfective.","fr":"Demandez «что делать?» → imperfectif ; «что сделать?» → perfectif. Un résultat unique ou un préfixe (про-, на-, с-) signale souvent le perfectif.","fa":"بپرس «что делать؟» → ناتمام؛ «что сделать؟» → کامل. یک نتیجهٔ یکباره یا یک پیشوند (про-، на-، с-) اغلب نشانهٔ نمود کامل است.","uk":"Запитай «что делать?» → недоконаний; «что сделать?» → доконаний. Одноразовий результат чи префікс (про-, на-, с-) часто вказує на доконаний вид.","ar_sy":"اسأل «что делать؟» → ناقص؛ «что сделать؟» → تام. النتيجة لمرة وحدة أو سابقة (про-، на-، с-) غالباً بتدل عالتام."}},
{"id":"budushchee-vremya","icon":"🔮","level":"A2","title":{"ru":"Будущее время: сложное и простое","de":"Futur: zusammengesetzt und einfach","en":"Future tense: compound and simple","fr":"Le futur : composé et simple","fa":"زمان آینده: مرکب و ساده","uk":"Майбутній час: складений і простий","ar_sy":"المستقبل: المركّب والبسيط"},"intro":{"ru":"В русском есть два будущих времени, и вид глагола решает, какое использовать. Сложное будущее образуется от глагола «быть» (буду, будешь…) плюс несовершенный инфинитив и описывает процесс. Простое будущее — это форма совершенного глагола, спрягаемая как настоящее время, и описывает законченное действие.","de":"Im Russischen gibt es zwei Futurformen, und der Aspekt entscheidet, welche man nimmt. Das zusammengesetzte Futur bildet man mit «быть» (буду, будешь…) plus unvollendetem Infinitiv und beschreibt einen Prozess. Das einfache Futur ist die wie das Präsens konjugierte Form des vollendeten Verbs und beschreibt eine abgeschlossene Handlung.","en":"Russian has two future tenses, and the verb's aspect decides which one you use. The compound future is formed with «быть» (буду, будешь…) plus an imperfective infinitive and describes a process. The simple future is a perfective verb conjugated like the present tense and describes a completed action.","fr":"Le russe a deux futurs, et l'aspect du verbe détermine lequel employer. Le futur composé se forme avec «быть» (буду, будешь…) plus l'infinitif imperfectif et décrit un processus. Le futur simple est un verbe perfectif conjugué comme le présent et décrit une action achevée.","fa":"روسی دو زمان آینده دارد و نمود فعل تعیین می‌کند کدام را به کار ببری. آیندهٔ مرکب با «быть» (буду، будешь…) به‌علاوهٔ مصدر ناتمام ساخته می‌شود و روند را توصیف می‌کند. آیندهٔ ساده فعل کامل است که مثل زمان حال صرف می‌شود و کنش پایان‌یافته را نشان می‌دهد.","uk":"У російській два майбутні часи, і вид дієслова вирішує, який уживати. Складений майбутній утворюється від «быть» (буду, будешь…) плюс недоконаний інфінітив і описує процес. Простий майбутній — це доконане дієслово, що дієвідмінюється як теперішній час, і описує завершену дію.","ar_sy":"بالروسي في نوعين مستقبل، ونوع الفعل بيقرّر أي واحد بتستعمل. المستقبل المركّب بيتكوّن من «быть» (буду، будешь…) مع مصدر ناقص وبيوصف عملية. المستقبل البسيط هو فعل تام بينصرف متل الحاضر وبيوصف فعل خلص."},"tables":[{"caption":{"ru":"Сложное будущее: буду + инфинитив (читать)","de":"Zusammengesetztes Futur: буду + Infinitiv (читать)","en":"Compound future: буду + infinitive (читать)","fr":"Futur composé : буду + infinitif (читать)","fa":"آیندهٔ مرکب: буду + مصدر (читать)","uk":"Складений майбутній: буду + інфінітив (читать)","ar_sy":"المستقبل المركّب: буду + المصدر (читать)"},"labelHeader":{"ru":"Лицо","de":"Person","en":"Person","fr":"Personne","fa":"شخص","uk":"Особа","ar_sy":"الضمير"},"columns":[{"ru":"Сложное (процесс)","de":"Zusammengesetzt (Prozess)","en":"Compound (process)","fr":"Composé (processus)","fa":"مرکب (روند)","uk":"Складений (процес)","ar_sy":"المركّب (عملية)"},{"ru":"Простое (результат)","de":"Einfach (Ergebnis)","en":"Simple (result)","fr":"Simple (résultat)","fa":"ساده (نتیجه)","uk":"Простий (результат)","ar_sy":"البسيط (نتيجة)"}],"rows":[{"label":{"ru":"я","de":"ich","en":"I","fr":"je","fa":"من","uk":"я","ar_sy":"أنا"},"cells":["буду читать","прочитаю"]},{"label":{"ru":"ты","de":"du","en":"you (sg.)","fr":"tu","fa":"تو","uk":"ти","ar_sy":"إنت"},"cells":["будешь читать","прочитаешь"]},{"label":{"ru":"он / она","de":"er / sie","en":"he / she","fr":"il / elle","fa":"او","uk":"він / вона","ar_sy":"هو / هي"},"cells":["будет читать","прочитает"]},{"label":{"ru":"мы","de":"wir","en":"we","fr":"nous","fa":"ما","uk":"ми","ar_sy":"نحنا"},"cells":["будем читать","прочитаем"]},{"label":{"ru":"вы","de":"ihr / Sie","en":"you (pl.)","fr":"vous","fa":"شما","uk":"ви","ar_sy":"إنتو"},"cells":["будете читать","прочитаете"]},{"label":{"ru":"они","de":"sie (Pl.)","en":"they","fr":"ils / elles","fa":"آن‌ها","uk":"вони","ar_sy":"هنّي"},"cells":["будут читать","прочитают"]}]}],"examples":[{"ru":"Завтра я буду работать весь день. — длительный процесс","de":"Morgen werde ich den ganzen Tag arbeiten. — andauernder Prozess","en":"Tomorrow I will be working all day. — ongoing process","fr":"Demain je travaillerai toute la journée. — processus continu","fa":"فردا تمام روز کار خواهم کرد. — روند مستمر","uk":"Завтра я працюватиму весь день. — тривалий процес","ar_sy":"بكرا رح اشتغل طول النهار. — عملية مستمرة"},{"ru":"Я напишу письмо и сразу отправлю его. — законченный результат","de":"Ich werde den Brief schreiben und ihn sofort abschicken. — abgeschlossenes Ergebnis","en":"I will write the letter and send it right away. — completed result","fr":"J'écrirai la lettre et l'enverrai tout de suite. — résultat achevé","fa":"نامه را خواهم نوشت و فوراً می‌فرستمش. — نتیجهٔ کامل","uk":"Я напишу листа й одразу відправлю його. — завершений результат","ar_sy":"رح اكتب المكتوب وابعتو دغري. — نتيجة خلصانة"},{"ru":"Когда ты будешь готовить ужин, я накрою на стол.","de":"Während du das Abendessen kochst, decke ich den Tisch.","en":"While you are cooking dinner, I will set the table.","fr":"Pendant que tu prépareras le dîner, je mettrai la table.","fa":"وقتی شام درست می‌کنی، من میز را می‌چینم.","uk":"Поки ти готуватимеш вечерю, я накрию на стіл.","ar_sy":"وقت ما تكون عم تطبخ العشا، أنا رح جهّز الطاولة."}],"hints":{"de":"Prozess in der Zukunft → буду + unvollendeter Infinitiv. Einmaliges Ergebnis → vollendetes Verb allein (kein буду!). «Я буду купить» ist falsch — sage «Я куплю».","en":"Process in the future → буду + imperfective infinitive. A single result → the perfective verb alone (no буду!). «Я буду купить» is wrong — say «Я куплю».","fr":"Processus au futur → буду + infinitif imperfectif. Résultat unique → verbe perfectif seul (pas de буду !). «Я буду купить» est faux — dites «Я куплю».","fa":"روند در آینده → буду + مصدر ناتمام. نتیجهٔ یکباره → فعل کامل به‌تنهایی (بدون буду!). «Я буду купить» غلط است — بگو «Я куплю».","uk":"Процес у майбутньому → буду + недоконаний інфінітив. Одноразовий результат → доконане дієслово саме (без буду!). «Я буду купить» — помилка, кажи «Я куплю».","ar_sy":"عملية بالمستقبل → буду + مصدر ناقص. نتيجة لمرة وحدة → الفعل التام لحالو (بلا буду!). «Я буду купить» غلط — قول «Я куплю»."}},
{"id":"glagoly-dvizheniya","icon":"🚶","level":"A2","title":{"ru":"Глаголы движения: идти / ходить, ехать / ездить","de":"Verben der Bewegung: идти / ходить, ехать / ездить","en":"Verbs of motion: идти / ходить, ехать / ездить","fr":"Les verbes de mouvement : идти / ходить, ехать / ездить","fa":"افعال حرکت: идти / ходить، ехать / ездить","uk":"Дієслова руху: идти / ходить, ехать / ездить","ar_sy":"أفعال الحركة: идти / ходить، ехать / ездить"},"intro":{"ru":"Русские глаголы движения делятся на две группы. Однонаправленные (идти, ехать) описывают движение в одну сторону, здесь и сейчас. Разнонаправленные (ходить, ездить) описывают движение туда-обратно, повторяющееся или вообще. «Идти» и «ходить» — пешком, «ехать» и «ездить» — на транспорте.","de":"Russische Bewegungsverben teilen sich in zwei Gruppen. Einläufige (идти, ехать) beschreiben eine Bewegung in eine Richtung, hier und jetzt. Mehrläufige (ходить, ездить) beschreiben Hin- und Rückbewegung, Wiederholung oder Allgemeines. «Идти/ходить» zu Fuß, «ехать/ездить» mit einem Verkehrsmittel.","en":"Russian verbs of motion split into two groups. Unidirectional verbs (идти, ехать) describe movement in one direction, here and now. Multidirectional verbs (ходить, ездить) describe round trips, repetition or motion in general. «Идти/ходить» is on foot, «ехать/ездить» is by vehicle.","fr":"Les verbes de mouvement russes se divisent en deux groupes. Les unidirectionnels (идти, ехать) décrivent un mouvement dans une seule direction, ici et maintenant. Les multidirectionnels (ходить, ездить) décrivent un aller-retour, une répétition ou un mouvement en général. «Идти/ходить» à pied, «ехать/ездить» en véhicule.","fa":"افعال حرکت روسی به دو گروه تقسیم می‌شوند. یک‌جهته (идти، ехать) حرکت در یک جهت را همین‌جا و همین حالا توصیف می‌کنند. چندجهته (ходить، ездить) رفت‌وبرگشت، تکرار یا حرکت به‌طور کلی را نشان می‌دهند. «идти/ходить» پیاده و «ехать/ездить» با وسیلهٔ نقلیه است.","uk":"Російські дієслова руху поділяються на дві групи. Односпрямовані (идти, ехать) описують рух в один бік, тут і зараз. Різноспрямовані (ходить, ездить) описують рух туди-назад, повторюваний або взагалі. «Идти/ходить» — пішки, «ехать/ездить» — транспортом.","ar_sy":"أفعال الحركة بالروسي بتنقسم لمجموعتين. الأحادية الاتجاه (идти، ехать) بتوصف حركة باتجاه واحد، هلق وهون. المتعددة الاتجاه (ходить، ездить) بتوصف رواح ورجعة، أو تكرار، أو حركة بشكل عام. «идти/ходить» عالإجر، و«ехать/ездить» بواسطة نقل."},"tables":[{"caption":{"ru":"Однонаправленные и разнонаправленные глаголы","de":"Einläufige und mehrläufige Verben","en":"Unidirectional and multidirectional verbs","fr":"Verbes unidirectionnels et multidirectionnels","fa":"افعال یک‌جهته و چندجهته","uk":"Односпрямовані та різноспрямовані дієслова","ar_sy":"الأفعال الأحادية والمتعددة الاتجاه"},"labelHeader":{"ru":"Значение","de":"Bedeutung","en":"Meaning","fr":"Sens","fa":"معنی","uk":"Значення","ar_sy":"المعنى"},"columns":[{"ru":"Однонаправленный","de":"Einläufig","en":"Unidirectional","fr":"Unidirectionnel","fa":"یک‌جهته","uk":"Односпрямований","ar_sy":"أحادي الاتجاه"},{"ru":"Разнонаправленный","de":"Mehrläufig","en":"Multidirectional","fr":"Multidirectionnel","fa":"چندجهته","uk":"Різноспрямований","ar_sy":"متعدد الاتجاه"}],"rows":[{"label":{"ru":"пешком","de":"zu Fuß","en":"on foot","fr":"à pied","fa":"پیاده","uk":"пішки","ar_sy":"عالإجر"},"cells":["идти","ходить"]},{"label":{"ru":"на транспорте","de":"mit Fahrzeug","en":"by vehicle","fr":"en véhicule","fa":"با وسیله","uk":"транспортом","ar_sy":"بواسطة نقل"},"cells":["ехать","ездить"]},{"label":{"ru":"я (наст. вр.)","de":"ich (Präsens)","en":"I (present)","fr":"je (présent)","fa":"من (حال)","uk":"я (тепер.)","ar_sy":"أنا (حاضر)"},"cells":["иду / еду","хожу / езжу"]},{"label":{"ru":"он (наст. вр.)","de":"er (Präsens)","en":"he (present)","fr":"il (présent)","fa":"او (حال)","uk":"він (тепер.)","ar_sy":"هو (حاضر)"},"cells":["идёт / едет","ходит / ездит"]}]}],"examples":[{"ru":"Сейчас я иду в магазин. — одно направление, прямо сейчас","de":"Jetzt gehe ich in den Laden. — eine Richtung, gerade jetzt","en":"Right now I'm walking to the shop. — one direction, at this moment","fr":"En ce moment, je vais au magasin. — une direction, maintenant","fa":"الان دارم به مغازه می‌روم. — یک جهت، همین حالا","uk":"Зараз я йду в магазин. — один напрямок, просто зараз","ar_sy":"هلق عم روح عالدكان. — اتجاه واحد، بهاللحظة"},{"ru":"Каждый день я хожу в спортзал. — регулярно, туда и обратно","de":"Jeden Tag gehe ich ins Fitnessstudio. — regelmäßig, hin und zurück","en":"Every day I go to the gym. — regularly, there and back","fr":"Chaque jour je vais à la salle de sport. — régulièrement, aller-retour","fa":"هر روز به باشگاه می‌روم. — منظم، رفت‌وبرگشت","uk":"Щодня я ходжу до спортзалу. — регулярно, туди й назад","ar_sy":"كل يوم بروح عالنادي. — بشكل منتظم، رواح ورجعة"},{"ru":"Летом мы едем в Москву, а вообще мы часто ездим за границу.","de":"Im Sommer fahren wir nach Moskau, aber generell fahren wir oft ins Ausland.","en":"In summer we're going to Moscow, but in general we often travel abroad.","fr":"Cet été nous allons à Moscou, mais en général nous voyageons souvent à l'étranger.","fa":"تابستان به مسکو می‌رویم، ولی به‌طور کلی اغلب به خارج سفر می‌کنیم.","uk":"Улітку ми їдемо до Москви, а взагалі ми часто їздимо за кордон.","ar_sy":"بالصيف نحنا رايحين عاموسكو، بس بشكل عام منروح كتير عبرّا."}],"hints":{"de":"Einmalige Fahrt jetzt in eine Richtung → идти/ехать. Gewohnheit, Wiederholung oder Hin und Zurück → ходить/ездить. «Я хожу в школу» = jeden Tag; «Я иду в школу» = gerade jetzt.","en":"A single trip now in one direction → идти/ехать. A habit, repetition or round trip → ходить/ездить. «Я хожу в школу» = every day; «Я иду в школу» = right now.","fr":"Un trajet unique maintenant dans une direction → идти/ехать. Une habitude, une répétition ou un aller-retour → ходить/ездить. «Я хожу в школу» = tous les jours ; «Я иду в школу» = maintenant.","fa":"یک سفر یکباره الان در یک جهت → идти/ехать. عادت، تکرار یا رفت‌وبرگشت → ходить/ездить. «Я хожу в школу» = هر روز؛ «Я иду в школу» = همین حالا.","uk":"Одна поїздка зараз в один бік → идти/ехать. Звичка, повторення чи туди-назад → ходить/ездить. «Я хожу в школу» = щодня; «Я иду в школу» = просто зараз.","ar_sy":"رحلة وحدة هلق باتجاه واحد → идти/ехать. عادة أو تكرار أو رواح ورجعة → ходить/ездить. «Я хожу в школу» = كل يوم؛ «Я иду в школу» = هلق."}},
{"id":"prityazhatelnye-prilagatelnye","icon":"🎨","level":"A2","title":{"ru":"Притяжательные местоимения и согласование прилагательных","de":"Possessivpronomen und Adjektivkongruenz","en":"Possessives and adjective agreement","fr":"Les possessifs et l'accord des adjectifs","fa":"ضمایر ملکی و مطابقت صفت","uk":"Присвійні займенники та узгодження прикметників","ar_sy":"ضمائر الملكية ومطابقة الصفات"},"intro":{"ru":"Притяжательные местоимения (мой, твой, наш, ваш) и прилагательные согласуются с существительным в роде, числе и падеже. Мужской род оканчивается на -ой/-ый/-ий, женский на -ая, средний на -ое, множественное число на -ые/-ие. Местоимения «его», «её», «их» не изменяются.","de":"Possessivpronomen (мой, твой, наш, ваш) und Adjektive kongruieren mit dem Substantiv in Genus, Numerus und Kasus. Maskulinum endet auf -ой/-ый/-ий, Femininum auf -ая, Neutrum auf -ое, Plural auf -ые/-ие. Die Pronomen «его», «её», «их» sind unveränderlich.","en":"Possessives (мой, твой, наш, ваш) and adjectives agree with the noun in gender, number and case. Masculine ends in -ой/-ый/-ий, feminine in -ая, neuter in -ое, plural in -ые/-ие. The pronouns «его», «её», «их» never change.","fr":"Les possessifs (мой, твой, наш, ваш) et les adjectifs s'accordent avec le nom en genre, nombre et cas. Le masculin finit en -ой/-ый/-ий, le féminin en -ая, le neutre en -ое, le pluriel en -ые/-ие. Les pronoms «его», «её», «их» sont invariables.","fa":"ضمایر ملکی (мой، твой، наш، ваш) و صفت‌ها با اسم در جنس، شمار و حالت مطابقت می‌کنند. مذکر به -ой/-ый/-ий، مؤنث به -ая، خنثی به -ое و جمع به -ые/-ие ختم می‌شود. ضمایر «его»، «её»، «их» هرگز تغییر نمی‌کنند.","uk":"Присвійні займенники (мой, твой, наш, ваш) і прикметники узгоджуються з іменником у роді, числі й відмінку. Чоловічий рід закінчується на -ой/-ый/-ий, жіночий на -ая, середній на -ое, множина на -ые/-ие. Займенники «его», «её», «их» не змінюються.","ar_sy":"ضمائر الملكية (мой، твой، наш، ваш) والصفات بتطابق الاسم بالجنس والعدد والحالة. المذكّر بينتهي بـ -ой/-ый/-ий، المؤنّث بـ -ая، المحايد بـ -ое، والجمع بـ -ые/-ие. الضمائر «его»، «её»، «их» ما بتتغيّر أبداً."},"tables":[{"caption":{"ru":"«Мой» и прилагательное «новый» по родам (именительный падеж)","de":"«Мой» und das Adjektiv «новый» nach Genus (Nominativ)","en":"«Мой» and the adjective «новый» by gender (nominative)","fr":"«Мой» et l'adjectif «новый» par genre (nominatif)","fa":"«Мой» و صفت «новый» بر پایهٔ جنس (نهادی)","uk":"«Мой» і прикметник «новый» за родами (називний відмінок)","ar_sy":"«Мой» والصفة «новый» حسب الجنس (حالة الرفع)"},"labelHeader":{"ru":"Род / число","de":"Genus / Numerus","en":"Gender / number","fr":"Genre / nombre","fa":"جنس / شمار","uk":"Рід / число","ar_sy":"الجنس / العدد"},"columns":[{"ru":"«Мой»","de":"«Mein»","en":"«My»","fr":"«Mon»","fa":"«مالِ من»","uk":"«Мій»","ar_sy":"«تبعي»"},{"ru":"Прилагательное + существительное","de":"Adjektiv + Substantiv","en":"Adjective + noun","fr":"Adjectif + nom","fa":"صفت + اسم","uk":"Прикметник + іменник","ar_sy":"صفة + اسم"}],"rows":[{"label":{"ru":"муж. род","de":"Maskulinum","en":"masculine","fr":"masculin","fa":"مذکر","uk":"чол. рід","ar_sy":"مذكّر"},"cells":["мой","мой новый дом"]},{"label":{"ru":"жен. род","de":"Femininum","en":"feminine","fr":"féminin","fa":"مؤنث","uk":"жін. рід","ar_sy":"مؤنّث"},"cells":["моя","моя новая машина"]},{"label":{"ru":"ср. род","de":"Neutrum","en":"neuter","fr":"neutre","fa":"خنثی","uk":"сер. рід","ar_sy":"محايد"},"cells":["моё","моё новое окно"]},{"label":{"ru":"мн. число","de":"Plural","en":"plural","fr":"pluriel","fa":"جمع","uk":"множина","ar_sy":"جمع"},"cells":["мои","мои новые друзья"]}]},{"caption":{"ru":"Притяжательные местоимения по лицам","de":"Possessivpronomen nach Person","en":"Possessive pronouns by person","fr":"Pronoms possessifs par personne","fa":"ضمایر ملکی بر پایهٔ شخص","uk":"Присвійні займенники за особами","ar_sy":"ضمائر الملكية حسب الشخص"},"labelHeader":{"ru":"Владелец","de":"Besitzer","en":"Owner","fr":"Possesseur","fa":"دارنده","uk":"Власник","ar_sy":"المالك"},"columns":[{"ru":"муж.","de":"mask.","en":"masc.","fr":"masc.","fa":"مذکر","uk":"чол.","ar_sy":"مذكّر"},{"ru":"жен.","de":"fem.","en":"fem.","fr":"fém.","fa":"مؤنث","uk":"жін.","ar_sy":"مؤنّث"},{"ru":"мн.","de":"Pl.","en":"pl.","fr":"pl.","fa":"جمع","uk":"мн.","ar_sy":"جمع"}],"rows":[{"label":{"ru":"я","de":"ich","en":"I","fr":"je","fa":"من","uk":"я","ar_sy":"أنا"},"cells":["мой","моя","мои"]},{"label":{"ru":"ты","de":"du","en":"you (sg.)","fr":"tu","fa":"تو","uk":"ти","ar_sy":"إنت"},"cells":["твой","твоя","твои"]},{"label":{"ru":"мы","de":"wir","en":"we","fr":"nous","fa":"ما","uk":"ми","ar_sy":"نحنا"},"cells":["наш","наша","наши"]},{"label":{"ru":"вы","de":"ihr / Sie","en":"you (pl.)","fr":"vous","fa":"شما","uk":"ви","ar_sy":"إنتو"},"cells":["ваш","ваша","ваши"]}]}],"examples":[{"ru":"Это мой старший брат и моя младшая сестра.","de":"Das ist mein älterer Bruder und meine jüngere Schwester.","en":"This is my older brother and my younger sister.","fr":"C'est mon frère aîné et ma sœur cadette.","fa":"این برادر بزرگ‌تر من و خواهر کوچک‌تر من است.","uk":"Це мій старший брат і моя молодша сестра.","ar_sy":"هاد أخي الكبير وهاي أختي الصغيرة."},{"ru":"Наши новые соседи очень дружелюбные.","de":"Unsere neuen Nachbarn sind sehr freundlich.","en":"Our new neighbours are very friendly.","fr":"Nos nouveaux voisins sont très sympathiques.","fa":"همسایه‌های جدید ما خیلی خوش‌برخوردند.","uk":"Наші нові сусіди дуже привітні.","ar_sy":"جيراننا الجداد كتير لطاف."},{"ru":"Твоя красная сумка лежит на его столе.","de":"Deine rote Tasche liegt auf seinem Tisch.","en":"Your red bag is lying on his table.","fr":"Ton sac rouge est posé sur sa table.","fa":"کیف قرمز تو روی میز او است.","uk":"Твоя червона сумка лежить на його столі.","ar_sy":"شنطتك الحمرا موجودة عطاولتو."}],"hints":{"de":"Adjektiv und Possessiv richten sich nach dem Substantiv, nicht nach dir: моя книга (Femininum), auch wenn ein Mann spricht. «Его/её/их» bleiben immer gleich — его дом, его машина, его дети.","en":"The adjective and possessive follow the noun, not the speaker: моя книга (feminine) even if a man says it. «Его/её/их» stay the same everywhere — его дом, его машина, его дети.","fr":"L'adjectif et le possessif s'accordent avec le nom, pas avec le locuteur : моя книга (féminin) même si c'est un homme qui parle. «Его/её/их» restent invariables — его дом, его машина, его дети.","fa":"صفت و ضمیر ملکی از اسم پیروی می‌کنند نه از گوینده: моя книга (مؤنث) حتی اگر مرد بگوید. «его/её/их» همیشه ثابت‌اند — его дом، его машина، его дети.","uk":"Прикметник і присвійний займенник узгоджуються з іменником, а не з мовцем: моя книга (жіночий рід), навіть якщо каже чоловік. «Его/её/их» незмінні — его дом, его машина, его дети.","ar_sy":"الصفة وضمير الملكية بيتبعوا الاسم مو الحكّي: моя книга (مؤنّث) حتى لو رجّال حكاها. «его/её/их» بتضل متل ما هي — его дом، его машина، его дети."}},
{"id":"obzor-padezhey","icon":"🗂️","level":"B1","title":{"ru":"Обзор всех шести падежей","de":"Überblick über alle sechs Fälle","en":"Overview of all six cases","fr":"Vue d'ensemble des six cas","fa":"مرور کلی هر شش حالت","uk":"Огляд усіх шести відмінків","ar_sy":"نظرة عامة على الحالات الست كلها"},"intro":{"ru":"В русском шесть падежей. Каждый отвечает на свои вопросы и меняет окончание слова. Именительный — это словарная форма (кто? что?), остальные пять называют «косвенными». Порядок и вопросы: именительный (кто/что), родительный (кого/чего — принадлежность, отрицание, «нет»), дательный (кому/чему — адресат), винительный (кого/что — прямой объект), творительный (кем/чем — орудие, «с»), предложный (о ком/о чём — всегда с предлогом). Ниже сводная таблица окончаний и главных значений.","de":"Das Russische hat sechs Fälle. Jeder beantwortet eigene Fragen und verändert die Wortendung. Der Nominativ ist die Wörterbuchform (wer? was?), die anderen fünf heißen „oblique“ Fälle. Reihenfolge und Fragen: Nominativ (wer/was), Genitiv (wessen — Besitz, Verneinung, „kein“), Dativ (wem — Empfänger), Akkusativ (wen/was — direktes Objekt), Instrumental (womit — Werkzeug, „mit“), Präpositiv (über wen/was — immer mit Präposition). Unten eine Übersicht der Endungen und Hauptbedeutungen.","en":"Russian has six cases. Each answers its own questions and changes the word ending. The nominative is the dictionary form (who? what?); the other five are called 'oblique'. Order and questions: nominative (who/what), genitive (of whom/what — possession, negation, 'no'), dative (to whom — recipient), accusative (whom/what — direct object), instrumental (by/with what — tool, 'with'), prepositional (about whom/what — always with a preposition). Below is a summary of endings and core uses.","fr":"Le russe a six cas. Chacun répond à ses propres questions et modifie la terminaison du mot. Le nominatif est la forme du dictionnaire (qui ? quoi ?) ; les cinq autres sont dits « obliques ». Ordre et questions : nominatif (qui/quoi), génitif (de qui/quoi — possession, négation, « pas de »), datif (à qui — destinataire), accusatif (qui/quoi — objet direct), instrumental (par/avec quoi — outil, « avec »), prépositionnel (sur qui/quoi — toujours avec préposition). Voici un tableau récapitulatif des terminaisons et des emplois principaux.","fa":"روسی شش حالت دارد. هر کدام به پرسش‌های خودش پاسخ می‌دهد و پایانهٔ واژه را تغییر می‌دهد. حالت نهادی شکل فرهنگ‌لغتی است (چه کسی؟ چه چیزی؟)؛ پنج حالت دیگر «غیرمستقیم» نامیده می‌شوند. ترتیب و پرسش‌ها: نهادی (که/چه)، اضافی (از چه کسی/چه چیزی — مالکیت، نفی، «نیست»)، برایی (به چه کسی — گیرنده)، مفعولی (چه کسی/چه چیزی — مفعول مستقیم)، بایی (با/به‌وسیلهٔ چه — ابزار، «با»)، حرف‌اضافه‌ای (دربارهٔ چه کسی/چه چیزی — همیشه با حرف اضافه). در جدول زیر خلاصهٔ پایانه‌ها و کاربردهای اصلی آمده است.","uk":"У російській шість відмінків. Кожен відповідає на свої питання й змінює закінчення слова. Називний — це словникова форма (хто? що?), решта п'ять називають «непрямими». Порядок і питання: називний (хто/що), родовий (кого/чого — належність, заперечення, «немає»), давальний (кому/чому — адресат), знахідний (кого/що — прямий об'єкт), орудний (ким/чим — знаряддя, «з»), місцевий (про кого/про що — завжди з прийменником). Нижче зведена таблиця закінчень і головних значень.","ar_sy":"بالروسي في ست حالات إعرابية. كل وحدة بتجاوب على أسئلتها وبتغيّر آخر الكلمة. حالة الرفع هي شكل القاموس (مين؟ شو؟)، والخمسة الباقيين بيسمّوهن حالات «غير مباشرة». الترتيب والأسئلة: الرفع (مين/شو)، الجر/المضاف إليه (لمين/لشو — ملكية، نفي، «ما في»)، حالة المفعول لأجله/الداتيف (لمين — المستقبِل)، حالة المفعول به (مين/شو — مفعول مباشر)، حالة الأداة (بشو — أداة، «مع»)، حالة الحرف (عن مين/عن شو — دايمًا مع حرف جر). تحت في جدول ملخّص للنهايات والاستعمالات الأساسية."},"tables":[{"caption":{"ru":"Шесть падежей: вопросы, типичные окончания, главное значение","de":"Sechs Fälle: Fragen, typische Endungen, Hauptbedeutung","en":"Six cases: questions, typical endings, core meaning","fr":"Six cas : questions, terminaisons typiques, sens principal","fa":"شش حالت: پرسش‌ها، پایانه‌های رایج، معنای اصلی","uk":"Шість відмінків: питання, типові закінчення, головне значення","ar_sy":"الحالات الست: الأسئلة، النهايات الشائعة، المعنى الأساسي"},"labelHeader":{"ru":"Падеж","de":"Fall","en":"Case","fr":"Cas","fa":"حالت","uk":"Відмінок","ar_sy":"الحالة"},"columns":[{"ru":"Вопрос","de":"Frage","en":"Question","fr":"Question","fa":"پرسش","uk":"Питання","ar_sy":"السؤال"},{"ru":"Окончания (м/ж/с, мн.)","de":"Endungen (m/f/n, Pl.)","en":"Endings (m/f/n, pl.)","fr":"Terminaisons (m/f/n, pl.)","fa":"پایانه‌ها (مذکر/مؤنث/خنثی، جمع)","uk":"Закінчення (ч/ж/с, мн.)","ar_sy":"النهايات (مذكر/مؤنث/محايد، جمع)"},{"ru":"Главное значение","de":"Hauptbedeutung","en":"Core meaning","fr":"Sens principal","fa":"معنای اصلی","uk":"Головне значення","ar_sy":"المعنى الأساسي"}],"rows":[{"label":{"ru":"Именительный","de":"Nominativ","en":"Nominative","fr":"Nominatif","fa":"نهادی","uk":"Називний","ar_sy":"الرفع"},"cells":["кто? что?","-∅ / -а,-я / -о,-е; -ы,-и,-а","подлежащее"]},{"label":{"ru":"Родительный","de":"Genitiv","en":"Genitive","fr":"Génitif","fa":"اضافی","uk":"Родовий","ar_sy":"الجر"},"cells":["кого? чего?","-а,-я / -ы,-и / -а,-я; -ов,-∅,-ей","принадлежность, отрицание, «нет»"]},{"label":{"ru":"Дательный","de":"Dativ","en":"Dative","fr":"Datif","fa":"برایی","uk":"Давальний","ar_sy":"الداتيف"},"cells":["кому? чему?","-у,-ю / -е,-и / -у,-ю; -ам,-ям","адресат, «нравится»"]},{"label":{"ru":"Винительный","de":"Akkusativ","en":"Accusative","fr":"Accusatif","fa":"مفعولی","uk":"Знахідний","ar_sy":"المفعول به"},"cells":["кого? что?","как Им. или Род. / -у,-ю / = Им.; = Им./Род.","прямой объект"]},{"label":{"ru":"Творительный","de":"Instrumental","en":"Instrumental","fr":"Instrumental","fa":"بایی","uk":"Орудний","ar_sy":"الأداة"},"cells":["кем? чем?","-ом,-ем / -ой,-ей / -ом,-ем; -ами,-ями","орудие, «с кем»"]},{"label":{"ru":"Предложный","de":"Präpositiv","en":"Prepositional","fr":"Prépositionnel","fa":"حرف‌اضافه‌ای","uk":"Місцевий","ar_sy":"حالة الحرف"},"cells":["о ком? о чём? где?","-е,-и / -е,-и / -е; -ах,-ях","место, тема (только с предлогом)"]}]}],"examples":[{"ru":"Брат (Им.) друга (Род.) подарил сестре (Дат.) книгу (Вин.) с рисунком (Твор.) о море (Предл.).","de":"Der Bruder (Nom.) des Freundes (Gen.) schenkte der Schwester (Dat.) ein Buch (Akk.) mit einer Zeichnung (Instr.) über das Meer (Präp.).","en":"The friend's (gen.) brother (nom.) gave the sister (dat.) a book (acc.) with a drawing (instr.) about the sea (prep.).","fr":"Le frère (nom.) de l'ami (gén.) a offert à la sœur (dat.) un livre (acc.) avec un dessin (instr.) sur la mer (prép.).","fa":"برادرِ (نهادی) دوست (اضافی) به خواهر (برایی) کتابی (مفعولی) با نقاشی (بایی) دربارهٔ دریا (حرف‌اضافه‌ای) هدیه داد.","uk":"Брат (Наз.) друга (Род.) подарував сестрі (Дав.) книжку (Знах.) з малюнком (Оруд.) про море (Місц.).","ar_sy":"أخو (رفع) الصديق (جر) أهدى للأخت (داتيف) كتاب (مفعول به) مع رسمة (أداة) عن البحر (حرف)."},{"ru":"У меня (Род.) нет времени (Род.) — здесь родительный и после «у», и после «нет».","de":"Ich habe keine Zeit (Gen.) — hier steht der Genitiv nach „u“ und nach „net“.","en":"I have no time (gen.) — the genitive appears both after 'u' and after 'net'.","fr":"Je n'ai pas le temps (gén.) — le génitif apparaît après « u » et après « net ».","fa":"من وقت (اضافی) ندارم — اینجا حالت اضافی هم بعد از «у» و هم بعد از «нет» می‌آید.","uk":"У мене (Род.) немає часу (Род.) — тут родовий і після «у», і після «немає».","ar_sy":"ما عندي وقت (جر) — هون الجر بيجي بعد «у» وبعد «нет» كمان."},{"ru":"Я горжусь другом (Твор.) и еду в Москву (Вин.) на поезде (Предл.).","de":"Ich bin stolz auf den Freund (Instr.) und fahre mit dem Zug (Präp.) nach Moskau (Akk.).","en":"I am proud of my friend (instr.) and travel to Moscow (acc.) by train (prep.).","fr":"Je suis fier de mon ami (instr.) et je vais à Moscou (acc.) en train (prép.).","fa":"من به دوستم (بایی) افتخار می‌کنم و با قطار (حرف‌اضافه‌ای) به مسکو (مفعولی) می‌روم.","uk":"Я пишаюся другом (Оруд.) і їду до Москви (Знах.) поїздом (Оруд.).","ar_sy":"أنا فخور بصاحبي (أداة) ورايح ع موسكو (مفعول به) بالقطار (حرف)."}],"hints":{"de":"Lerne jeden Fall zusammen mit seiner Frage UND seinen typischen Auslösern (Präpositionen, Verben). Der Genitiv ist der arbeitsreichste: Besitz, Verneinung, Mengen, viele Präpositionen. Der Präpositiv steht NIE ohne Präposition.","en":"Learn each case together with its question AND its typical triggers (prepositions, verbs). The genitive is the busiest one: possession, negation, quantities, many prepositions. The prepositional NEVER stands without a preposition.","fr":"Apprenez chaque cas avec sa question ET ses déclencheurs typiques (prépositions, verbes). Le génitif est le plus chargé : possession, négation, quantités, nombreuses prépositions. Le prépositionnel ne s'emploie JAMAIS sans préposition.","fa":"هر حالت را همراه با پرسشش و نشانه‌های رایجش (حروف اضافه، افعال) یاد بگیرید. حالت اضافی پرکارترین است: مالکیت، نفی، مقدار، حروف اضافهٔ زیاد. حالت حرف‌اضافه‌ای هرگز بدون حرف اضافه نمی‌آید.","uk":"Вивчайте кожен відмінок разом із його питанням І типовими «пусковими» словами (прийменники, дієслова). Родовий — найзавантаженіший: належність, заперечення, кількість, багато прийменників. Місцевий НІКОЛИ не вживається без прийменника.","ar_sy":"احفظ كل حالة مع سؤالها ومع الكلمات اللي بتجرّها (حروف الجر، الأفعال). الجر هو أكتر وحدة شغّالة: ملكية، نفي، كميات، وحروف جر كتير. وحالة الحرف ما بتجي أبدًا بدون حرف جر."}},
{"id":"upotreblenie-vida","icon":"⏳","level":"B1","title":{"ru":"Употребление вида глагола","de":"Der Gebrauch des Verbalaspekts","en":"Using verbal aspect","fr":"L'emploi de l'aspect verbal","fa":"کاربرد نمود فعل","uk":"Уживання виду дієслова","ar_sy":"استعمال جانب الفعل (المظهر)"},"intro":{"ru":"Почти каждый русский глагол существует в паре: несовершенный вид (НСВ) и совершенный вид (СВ). Выбор зависит не от времени, а от того, КАК вы смотрите на действие. НСВ описывает процесс, повторение, факт «вообще», привычку, а также действие при отрицании («никогда не делал»). СВ описывает одно завершённое действие с результатом, единичный факт, начало или конец. Правило-подсказка: если важен результат («сделал и вот он») — СВ; если важен ход или регулярность — НСВ. В настоящем времени бывает только НСВ; будущее у СВ простое (сделаю), у НСВ сложное (буду делать).","de":"Fast jedes russische Verb existiert als Paar: unvollendeter Aspekt (impf) und vollendeter Aspekt (perf). Die Wahl hängt nicht von der Zeit ab, sondern davon, WIE man die Handlung betrachtet. Der impf beschreibt Prozess, Wiederholung, die bloße Tatsache, Gewohnheit sowie die Handlung bei Verneinung („hat nie getan“). Der perf beschreibt eine abgeschlossene Handlung mit Resultat, ein einmaliges Ereignis, Anfang oder Ende. Faustregel: Zählt das Resultat („getan, und da ist es“) — perf; zählt der Verlauf oder die Regelmäßigkeit — impf. Im Präsens gibt es nur den impf; das Futur ist beim perf einfach (sdelaju), beim impf zusammengesetzt (budu delatj).","en":"Almost every Russian verb comes as a pair: imperfective (impf) and perfective (perf). The choice depends not on tense but on HOW you view the action. The impf describes a process, repetition, the bare fact, a habit, and also the action under negation ('never did it'). The perf describes one completed action with a result, a single event, a beginning or an end. Rule of thumb: if the result matters ('did it, and here it is') — perf; if the flow or regularity matters — impf. The present tense has only impf; the future is simple for perf (sdelayu) but compound for impf (budu delat).","fr":"Presque chaque verbe russe forme une paire : imperfectif (impf) et perfectif (perf). Le choix ne dépend pas du temps mais de la MANIÈRE dont on envisage l'action. L'impf décrit un processus, une répétition, le simple fait, une habitude, ainsi que l'action sous la négation (« ne l'a jamais fait »). Le perf décrit une action unique achevée avec un résultat, un événement ponctuel, un début ou une fin. Règle pratique : si le résultat compte (« l'a fait, et le voilà ») — perf ; si le déroulement ou la régularité compte — impf. Le présent n'a que l'impf ; le futur est simple au perf (sdelaïou) mais composé à l'impf (boudou delat).","fa":"تقریباً هر فعل روسی به‌صورت جفت است: نمود ناتمام (impf) و نمود تمام (perf). انتخاب به زمان بستگی ندارد بلکه به این بستگی دارد که کنش را چگونه می‌بینید. impf روند، تکرار، خودِ واقعیت، عادت و نیز کنش در حالت نفی («هیچ‌وقت انجام نداد») را نشان می‌دهد. perf یک کنش کامل‌شده با نتیجه، رویداد یگانه، آغاز یا پایان را نشان می‌دهد. قاعدهٔ سرانگشتی: اگر نتیجه مهم باشد («انجام داد و اینجاست») — perf؛ اگر روند یا تکرار مهم باشد — impf. زمان حال فقط impf دارد؛ آینده در perf ساده است (sdelayu) و در impf مرکب (budu delat).","uk":"Майже кожне російське дієслово існує в парі: недоконаний вид (НВ) і доконаний вид (ДВ). Вибір залежить не від часу, а від того, ЯК ви дивитесь на дію. НВ описує процес, повторення, факт «взагалі», звичку, а також дію при запереченні («ніколи не робив»). ДВ описує одну завершену дію з результатом, поодинокий факт, початок або кінець. Правило-підказка: якщо важливий результат («зробив, і ось він») — ДВ; якщо важливий перебіг чи регулярність — НВ. У теперішньому часі буває лише НВ; майбутнє в ДВ просте (зроблю), у НВ складене (буду робити).","ar_sy":"كل فعل روسي تقريبًا بيجي بجوز: جانب غير تام (impf) وجانب تام (perf). الاختيار مو حسب الزمن، بل حسب كيف عم تشوف الفعل. الـimpf بيوصف العملية، التكرار، مجرد الحدث، العادة، وكمان الفعل مع النفي («عمره ما عمل»). الـperf بيوصف فعل واحد خلص وطلع منه نتيجة، حدث لمرة وحدة، بداية أو نهاية. قاعدة سريعة: إذا النتيجة مهمة («عملها وهي جاهزة») — perf؛ إذا المجرى أو التكرار مهم — impf. المضارع فيه بس impf؛ المستقبل بالـperf بسيط (سديلايو) وبالـimpf مركّب (بودو ديلات)."},"tables":[{"caption":{"ru":"Когда несовершенный, когда совершенный","de":"Wann unvollendet, wann vollendet","en":"When imperfective, when perfective","fr":"Quand l'imperfectif, quand le perfectif","fa":"کِی ناتمام، کِی تمام","uk":"Коли недоконаний, коли доконаний","ar_sy":"إيمتى غير تام، إيمتى تام"},"labelHeader":{"ru":"Ситуация","de":"Situation","en":"Situation","fr":"Situation","fa":"موقعیت","uk":"Ситуація","ar_sy":"الحالة"},"columns":[{"ru":"Несовершенный (НСВ)","de":"Unvollendet (impf)","en":"Imperfective (impf)","fr":"Imperfectif (impf)","fa":"ناتمام (impf)","uk":"Недоконаний (НВ)","ar_sy":"غير تام (impf)"},{"ru":"Совершенный (СВ)","de":"Vollendet (perf)","en":"Perfective (perf)","fr":"Perfectif (perf)","fa":"تمام (perf)","uk":"Доконаний (ДВ)","ar_sy":"تام (perf)"}],"rows":[{"label":{"ru":"Процесс / длительность","de":"Prozess / Dauer","en":"Process / duration","fr":"Processus / durée","fa":"روند / مدت","uk":"Процес / тривалість","ar_sy":"عملية / مدة"},"cells":["Он читал весь вечер.","—"]},{"label":{"ru":"Один результат","de":"Ein Resultat","en":"One result","fr":"Un résultat","fa":"یک نتیجه","uk":"Один результат","ar_sy":"نتيجة وحدة"},"cells":["—","Он прочитал книгу."]},{"label":{"ru":"Повторение / привычка","de":"Wiederholung / Gewohnheit","en":"Repetition / habit","fr":"Répétition / habitude","fa":"تکرار / عادت","uk":"Повторення / звичка","ar_sy":"تكرار / عادة"},"cells":["Каждый день делал зарядку.","—"]},{"label":{"ru":"Отрицание (не было факта)","de":"Verneinung (kein Fakt)","en":"Negation (no fact)","fr":"Négation (pas de fait)","fa":"نفی (رخ نداد)","uk":"Заперечення (не було факту)","ar_sy":"نفي (ما صار)"},"cells":["Я никогда не делал этого.","—"]},{"label":{"ru":"Начало / конец, «вдруг»","de":"Anfang / Ende, „plötzlich“","en":"Start / end, 'suddenly'","fr":"Début / fin, « soudain »","fa":"آغاز / پایان، «ناگهان»","uk":"Початок / кінець, «раптом»","ar_sy":"بداية / نهاية، «فجأة»"},"cells":["—","Она вдруг замолчала."]},{"label":{"ru":"Будущее время","de":"Futur","en":"Future tense","fr":"Futur","fa":"زمان آینده","uk":"Майбутній час","ar_sy":"زمن المستقبل"},"cells":["Я буду писать письмо.","Я напишу письмо."]}]}],"examples":[{"ru":"Вчера я весь день писал отчёт, но так и не написал его.","de":"Gestern habe ich den ganzen Tag am Bericht geschrieben, ihn aber doch nicht fertig geschrieben.","en":"Yesterday I wrote (was writing) the report all day, but still didn't finish it.","fr":"Hier, j'ai écrit le rapport toute la journée, mais je ne l'ai finalement pas terminé.","fa":"دیروز تمام روز داشتم گزارش را می‌نوشتم، اما در آخر تمامش نکردم.","uk":"Учора я цілий день писав звіт, але так і не написав його.","ar_sy":"مبارح ضل نهار كامل عم أكتب التقرير، بس بالآخر ما خلّصتو."},{"ru":"Обычно я готовлю ужин сам, но сегодня приготовила мама.","de":"Normalerweise koche ich das Abendessen selbst, aber heute hat es Mama gekocht.","en":"I usually cook dinner myself, but today Mom cooked it.","fr":"D'habitude je prépare le dîner moi-même, mais aujourd'hui c'est maman qui l'a préparé.","fa":"معمولاً خودم شام درست می‌کنم، اما امروز مامان درستش کرد.","uk":"Зазвичай я готую вечерю сам, але сьогодні приготувала мама.","ar_sy":"عادةً بطبخ العشا بنفسي، بس اليوم ماما طبختو."},{"ru":"Он открыл окно, сел за стол и начал работать.","de":"Er öffnete das Fenster, setzte sich an den Tisch und begann zu arbeiten.","en":"He opened the window, sat down at the desk, and started to work.","fr":"Il a ouvert la fenêtre, s'est assis à la table et s'est mis à travailler.","fa":"پنجره را باز کرد، پشت میز نشست و شروع به کار کرد.","uk":"Він відчинив вікно, сів за стіл і почав працювати.","ar_sy":"فتح الشباك، قعد ع الطاولة وبلّش يشتغل."}],"hints":{"de":"Frage dich: „Interessiert mich das Ergebnis oder der Verlauf?“ Ergebnis → perf, Verlauf → impf. Merke: verneinte Vergangenheit ist fast immer impf („ich habe es nie getan“), und nach Verben wie „beginnen, aufhören, fortsetzen“ steht IMMER der impf.","en":"Ask yourself: 'Do I care about the result or the process?' Result → perf, process → impf. Note: negated past is almost always impf ('I never did it'), and after verbs like 'begin, stop, continue' you ALWAYS use the impf.","fr":"Demandez-vous : « Ce qui m'importe, c'est le résultat ou le déroulement ? » Résultat → perf, déroulement → impf. Notez : le passé nié est presque toujours impf (« je ne l'ai jamais fait »), et après « commencer, arrêter, continuer » on emploie TOUJOURS l'impf.","fa":"از خودت بپرس: «نتیجه مهم است یا روند؟» نتیجه → perf، روند → impf. توجه: گذشتهٔ منفی تقریباً همیشه impf است («هیچ‌وقت انجامش ندادم»)، و بعد از افعالی مثل «شروع کردن، تمام کردن، ادامه دادن» همیشه impf می‌آید.","uk":"Спитайте себе: «Мене цікавить результат чи перебіг?» Результат → ДВ, перебіг → НВ. Зауважте: заперечене минуле майже завжди НВ («я ніколи цього не робив»), а після дієслів «починати, припиняти, продовжувати» ЗАВЖДИ вживають НВ.","ar_sy":"اسأل حالك: «يهمّني النتيجة ولا المجرى؟» النتيجة → perf، المجرى → impf. لاحظ: الماضي المنفي دايمًا تقريبًا impf («عمري ما عملتها»)، وبعد أفعال زي «بلّش، وقّف، كمّل» دايمًا بتستعمل الـimpf."}},
{"id":"pristavki-dvizheniya","icon":"↔️","level":"B1","title":{"ru":"Глаголы движения с приставками","de":"Bewegungsverben mit Präfixen","en":"Verbs of motion with prefixes","fr":"Les verbes de mouvement préfixés","fa":"افعال حرکت با پیشوند","uk":"Дієслова руху з префіксами","ar_sy":"أفعال الحركة مع السوابق (البادئات)"},"intro":{"ru":"К базовым глаголам движения (идти/ходить, ехать/ездить) можно добавить приставку, которая уточняет направление. Приставка меняет и значение, и вид: с однонаправленным глаголом (идти, ехать) она даёт СВ (прийти, приехать), а с многонаправленным (ходить, ездить) — НСВ (приходить, приезжать). Основные приставки: при- (прибытие, «сюда»), у- (уход, «прочь совсем»), в-/во- и вы- (внутрь / наружу), под- (приблизиться) и от-/ото- (отойти), по- (начало движения, «пойти»), за- (зайти по пути, заглянуть), про- (пройти мимо / сквозь). Многие требуют своих предлогов: при- + «в/на» и «к», у- + «из/с» и «от», вы- + «из».","de":"An die Grundverben der Bewegung (idti/chodit, echat/ezdit) kann man ein Präfix anhängen, das die Richtung präzisiert. Das Präfix ändert Bedeutung UND Aspekt: mit dem eindirektionalen Verb (idti, echat) ergibt es perf (prijti, priechat), mit dem mehrdirektionalen (chodit, ezdit) impf (prichodit, priezžat). Hauptpräfixe: pri- (Ankunft, „hierher“), u- (Weggang, „ganz weg“), v-/vo- und vy- (hinein / hinaus), pod- (sich nähern) und ot-/oto- (sich entfernen), po- (Beginn der Bewegung, „losgehen“), za- (unterwegs vorbeischauen), pro- (vorbei- / hindurchgehen). Viele verlangen eigene Präpositionen: pri- + „v/na“ und „k“, u- + „iz/s“ und „ot“, vy- + „iz“.","en":"To the basic verbs of motion (idti/khodit 'go on foot', ekhat/ezdit 'go by vehicle') you can add a prefix that specifies direction. The prefix changes both meaning AND aspect: with the unidirectional verb (idti, ekhat) it gives perfective (priyti, priyekhat), with the multidirectional (khodit, ezdit) imperfective (prikhodit, priyezzhat). Main prefixes: pri- (arrival, 'to here'), u- (departure, 'away for good'), v-/vo- and vy- (in / out), pod- (approach) and ot-/oto- (move away), po- (start of movement, 'set off'), za- (drop by on the way), pro- (go past / through). Many require their own prepositions: pri- + 'v/na' and 'k', u- + 'iz/s' and 'ot', vy- + 'iz'.","fr":"Aux verbes de base du mouvement (idti/khodit « aller à pied », iekhat/iezdit « aller en véhicule ») on peut ajouter un préfixe qui précise la direction. Le préfixe change à la fois le sens ET l'aspect : avec le verbe unidirectionnel (idti, iekhat) il donne le perfectif (priïti, priïekhat), avec le multidirectionnel (khodit, iezdit) l'imperfectif (prikhodit, priïezjat). Préfixes principaux : pri- (arrivée, « ici »), ou- (départ, « au loin définitivement »), v-/vo- et vy- (entrée / sortie), pod- (s'approcher) et ot-/oto- (s'éloigner), po- (début du mouvement, « partir »), za- (passer en chemin), pro- (passer devant / à travers). Beaucoup exigent leurs prépositions : pri- + « v/na » et « k », ou- + « iz/s » et « ot », vy- + « iz ».","fa":"به افعال پایهٔ حرکت (idti/khodit «رفتن پیاده»، yekhat/yezdit «رفتن با وسیله») می‌توان پیشوندی افزود که جهت را مشخص می‌کند. پیشوند هم معنا و هم نمود را عوض می‌کند: با فعل یک‌جهته (idti، yekhat) نمود تمام می‌سازد (priyti، priyekhat) و با فعل چندجهته (khodit، yezdit) نمود ناتمام (prikhodit، priyezzhat). پیشوندهای اصلی: pri- (رسیدن، «به اینجا»)، u- (رفتن، «برای همیشه دور»)، v-/vo- و vy- (به داخل / به بیرون)، pod- (نزدیک شدن) و ot-/oto- (دور شدن)، po- (آغاز حرکت، «راه افتادن»)، za- (سر راه سری زدن)، pro- (رد شدن از کنار / از میان). خیلی‌ها حرف اضافهٔ خودشان را می‌خواهند: pri- + «v/na» و «k»، u- + «iz/s» و «ot»، vy- + «iz».","uk":"До базових дієслів руху (идти/ходить, ехать/ездить) можна додати префікс, який уточнює напрямок. Префікс змінює і значення, і вид: з однонапрямленим дієсловом (идти, ехать) він дає ДВ (прийти, приехать), а з багатонапрямленим (ходить, ездить) — НВ (приходить, приезжать). Основні префікси: при- (прибуття, «сюди»), у- (відхід, «геть остаточно»), в-/во- і вы- (всередину / назовні), под- (наблизитися) і от-/ото- (відійти), по- (початок руху, «піти»), за- (зайти дорогою), про- (пройти повз / крізь). Багато вимагають своїх прийменників: при- + «в/на» і «к», у- + «из/с» і «от», вы- + «из».","ar_sy":"لأفعال الحركة الأساسية (idti/khodit «يمشي ع رجليه»، yekhat/yezdit «يروح بواسطة»)، فينا نضيف سابقة بتحدّد الاتجاه. السابقة بتغيّر المعنى والجانب سوا: مع الفعل باتجاه واحد (idti، yekhat) بتعطي perf (priyti، priyekhat)، ومع فعل عدة اتجاهات (khodit، yezdit) بتعطي impf (prikhodit، priyezzhat). أهم السوابق: pri- (وصول، «لهون»)، u- (مغادرة، «بعيد للأبد»)، v-/vo- وvy- (لجوا / لبرا)، pod- (يقرّب) وot-/oto- (يبعد)، po- (بداية الحركة، «راح»)، za- (يمرق يطلّ بالطريق)، pro- (يمرق من جنب / من خلال). كتير منهن بدهن حرف الجر تبعهن: pri- + «v/na» وk، u- + «iz/s» وot، vy- + «iz»."},"tables":[{"caption":{"ru":"Приставки направления (на примере идти → …ходить/…йти)","de":"Richtungspräfixe (am Beispiel idti → …chodit/…jti)","en":"Directional prefixes (example idti → …khodit/…yti)","fr":"Préfixes de direction (exemple idti → …khodit/…yti)","fa":"پیشوندهای جهت (نمونه idti → …khodit/…yti)","uk":"Префікси напрямку (на прикладі идти → …ходить/…йти)","ar_sy":"سوابق الاتجاه (مثال idti → …khodit/…yti)"},"labelHeader":{"ru":"Приставка","de":"Präfix","en":"Prefix","fr":"Préfixe","fa":"پیشوند","uk":"Префікс","ar_sy":"السابقة"},"columns":[{"ru":"Значение","de":"Bedeutung","en":"Meaning","fr":"Sens","fa":"معنا","uk":"Значення","ar_sy":"المعنى"},{"ru":"НСВ / СВ","de":"impf / perf","en":"impf / perf","fr":"impf / perf","fa":"impf / perf","uk":"НВ / ДВ","ar_sy":"impf / perf"},{"ru":"Предлог","de":"Präposition","en":"Preposition","fr":"Préposition","fa":"حرف اضافه","uk":"Прийменник","ar_sy":"حرف الجر"}],"rows":[{"label":{"ru":"при-","de":"pri-","en":"pri-","fr":"pri-","fa":"pri-","uk":"при-","ar_sy":"pri-"},"cells":["прибыть, приход сюда","приходить / прийти","в/на + Вин.; к + Дат."]},{"label":{"ru":"у-","de":"u-","en":"u-","fr":"ou-","fa":"u-","uk":"у-","ar_sy":"u-"},"cells":["уйти совсем, отсутствие","уходить / уйти","из/с + Род.; от + Род."]},{"label":{"ru":"в-/вы-","de":"v-/vy-","en":"v-/vy-","fr":"v-/vy-","fa":"v-/vy-","uk":"в-/ви-","ar_sy":"v-/vy-"},"cells":["войти внутрь / выйти наружу","входить-выходить / войти-выйти","в + Вин. / из + Род."]},{"label":{"ru":"под-","de":"pod-","en":"pod-","fr":"pod-","fa":"pod-","uk":"под-","ar_sy":"pod-"},"cells":["подойти, приблизиться","подходить / подойти","к + Дат."]},{"label":{"ru":"от-","de":"ot-","en":"ot-","fr":"ot-","fa":"ot-","uk":"от-","ar_sy":"ot-"},"cells":["отойти, отдалиться","отходить / отойти","от + Род."]},{"label":{"ru":"по-","de":"po-","en":"po-","fr":"po-","fa":"po-","uk":"по-","ar_sy":"po-"},"cells":["начать движение, «пойти»","— / пойти, поехать","в/на + Вин.; к + Дат."]},{"label":{"ru":"за-","de":"za-","en":"za-","fr":"za-","fa":"za-","uk":"за-","ar_sy":"za-"},"cells":["зайти по пути, заглянуть","заходить / зайти","в/на + Вин.; к + Дат.; за + Твор."]},{"label":{"ru":"про-","de":"pro-","en":"pro-","fr":"pro-","fa":"pro-","uk":"про-","ar_sy":"pro-"},"cells":["пройти мимо / сквозь","проходить / пройти","мимо + Род.; через + Вин."]}]}],"examples":[{"ru":"Я вышел из дома, дошёл до угла, перешёл дорогу и зашёл в магазин.","de":"Ich ging aus dem Haus, ging bis zur Ecke, überquerte die Straße und ging in den Laden hinein.","en":"I left the house, walked up to the corner, crossed the road, and dropped into the shop.","fr":"Je suis sorti de la maison, j'ai marché jusqu'au coin, j'ai traversé la route et je suis entré dans le magasin.","fa":"از خانه بیرون آمدم، تا سرِ نبش رفتم، از خیابان رد شدم و به مغازه سر زدم.","uk":"Я вийшов з дому, дійшов до рогу, перейшов дорогу і зайшов у магазин.","ar_sy":"طلعت من البيت، وصلت لعند الزاوية، قطعت الطريق وفتّ ع الدكان."},{"ru":"Гости приехали в семь, а уехали только под утро.","de":"Die Gäste kamen um sieben an und fuhren erst gegen Morgen wieder weg.","en":"The guests arrived at seven and left only towards morning.","fr":"Les invités sont arrivés à sept heures et ne sont repartis que vers le matin.","fa":"مهمان‌ها ساعت هفت رسیدند و تازه دمِ صبح رفتند.","uk":"Гості приїхали о сьомій, а поїхали тільки над ранок.","ar_sy":"الضيوف وصلوا الساعة سبعة وما راحوا إلا ع الفجر."},{"ru":"Подойди к доске, а потом отойди, чтобы все видели.","de":"Komm zur Tafel und geh dann wieder weg, damit alle es sehen.","en":"Come up to the board, then step back so everyone can see.","fr":"Approche-toi du tableau, puis éloigne-toi pour que tout le monde voie.","fa":"به تخته نزدیک شو، بعد کنار برو تا همه ببینند.","uk":"Підійди до дошки, а потім відійди, щоб усі бачили.","ar_sy":"قرّب ع اللوح، وبعدين ابعد تا يشوفوا الكل."}],"hints":{"de":"Denke an das Präfixpaar wie an Gegensätze: pri- (ankommen) ↔ u- (weggehen), v- (hinein) ↔ vy- (hinaus), pod- (näher) ↔ ot- (weiter weg). Und merke dir gleich die Präposition mit: uyti IZ doma, priyti V dom, podoyti K dveri.","en":"Think of the prefixes as opposites: pri- (arrive) ↔ u- (leave), v- (in) ↔ vy- (out), pod- (closer) ↔ ot- (away). And memorize the preposition together with the prefix: uyti IZ doma, priyti V dom, podoyti K dveri.","fr":"Pensez aux préfixes par paires opposées : pri- (arriver) ↔ ou- (partir), v- (entrer) ↔ vy- (sortir), pod- (se rapprocher) ↔ ot- (s'éloigner). Et mémorisez la préposition avec le préfixe : ouïti IZ doma, priïti V dom, podoïti K dveri.","fa":"پیشوندها را جفتِ متضاد در نظر بگیر: pri- (رسیدن) ↔ u- (رفتن)، v- (به داخل) ↔ vy- (به بیرون)، pod- (نزدیک‌تر) ↔ ot- (دورتر). و حرف اضافه را همراه پیشوند حفظ کن: uyti IZ doma، priyti V dom، podoyti K dveri.","uk":"Уявляйте префікси парами-протилежностями: при- (прибути) ↔ у- (піти), в- (всередину) ↔ ви- (назовні), под- (ближче) ↔ от- (далі). І запам'ятовуйте прийменник разом із префіксом: уйти ИЗ дому, прийти В дім, подойти К дверям.","ar_sy":"فكّر بالسوابق كأنها أضداد: pri- (يوصل) ↔ u- (يروح)، v- (لجوا) ↔ vy- (لبرا)، pod- (يقرّب) ↔ ot- (يبعد). واحفظ حرف الجر مع السابقة سوا: uyti IZ doma، priyti V dom، podoyti K dveri."}},
{"id":"povelitelnoe-naklonenie","icon":"📣","level":"B1","title":{"ru":"Повелительное наклонение","de":"Der Imperativ (Befehlsform)","en":"The imperative mood","fr":"Le mode impératif","fa":"وجه امری","uk":"Наказовий спосіб","ar_sy":"صيغة الأمر"},"intro":{"ru":"Повелительное наклонение выражает просьбу, приказ или совет. Образуется от основы настоящего/будущего времени (форма «они»): убираем окончание и смотрим на конец основы. Если основа кончается на гласную — прибавляем -й (читаj-ут → читай). Если на согласную и ударение на окончании — прибавляем -и (говор-ят → говори, ид-ут → иди). Если на согласную без ударения на окончании — прибавляем -ь (готов-ят → готовь, режут → режь). Форма на «вы» / вежливая добавляет -те: читайте, говорите. Выбор вида: для совершенного действия — СВ (Открой окно!), для отрицательного запрета и повторяемого — НСВ (Не открывай! Всегда закрывай дверь). Совместный призыв («давайте сделаем») строится через давай(те) + инфинитив НСВ или + форма «мы» СВ: давай пойдём, давайте петь.","de":"Der Imperativ drückt eine Bitte, einen Befehl oder einen Rat aus. Er wird vom Präsens-/Futurstamm gebildet (der „sie“-Form): Endung weg, dann auf das Stammende schauen. Endet der Stamm auf einen Vokal — hänge -j an (čitaj-ut → čitaj). Auf einen Konsonanten mit Endungsbetonung — hänge -i an (govor-jat → govori, id-ut → idi). Auf einen Konsonanten ohne Endungsbetonung — hänge -ь an (gotov-jat → gotovj, režut → režj). Die „Sie“-/Höflichkeitsform hängt -te an: čitajte, govorite. Aspektwahl: für eine abgeschlossene Handlung perf (Otkroj okno! — Mach das Fenster auf!), für ein Verbot und Wiederholtes impf (Ne otkryvaj! Vsegda zakryvaj dverj). Der gemeinsame Aufruf („lass(t) uns …“) mit davaj(te) + impf-Infinitiv oder + „wir“-Form perf: davaj pojdjom, davajte petj.","en":"The imperative mood expresses a request, command, or advice. It is formed from the present/future stem (the 'they' form): drop the ending and look at the stem's end. If the stem ends in a vowel — add -y (chitaj-ut → chitay). If in a consonant with stress on the ending — add -i (govor-yat → govori, id-ut → idi). If in a consonant without stress on the ending — add -ь (gotov-yat → gotov', rezhut → rezh'). The 'you (formal/plural)' form adds -te: chitayte, govorite. Aspect choice: for one completed action use perf (Otkroy okno! — Open the window!), for a prohibition and repeated actions use impf (Ne otkryvay! Vsegda zakryvay dver'). The joint call ('let's …') uses davay(te) + impf infinitive or + the 'we' perf form: davay poydyom, davayte pet'.","fr":"Le mode impératif exprime une demande, un ordre ou un conseil. Il se forme sur le radical du présent/futur (la forme « ils ») : on enlève la terminaison et on regarde la fin du radical. Si le radical finit par une voyelle — on ajoute -ï (tchitaï-out → tchitaï). Par une consonne avec accent sur la terminaison — on ajoute -i (govor-iat → govori, id-out → idi). Par une consonne sans accent sur la terminaison — on ajoute -ь (gotov-iat → gotov', rejout → rej'). La forme « vous » (poli/pluriel) ajoute -te : tchitaïte, govorite. Choix de l'aspect : pour une action achevée, le perf (Otkroï okno ! — Ouvre la fenêtre !) ; pour une interdiction et le répété, l'impf (Ne otkryvaï ! Vsegda zakryvaï dver'). L'appel commun (« allons… ») se fait avec davaï(te) + infinitif impf ou + la forme « nous » perf : davaï poïdiom, davaïte pet'.","fa":"وجه امری خواهش، دستور یا پند را بیان می‌کند. از ستاک زمان حال/آینده (صیغهٔ «آنها») ساخته می‌شود: پایانه را حذف کن و به آخر ستاک نگاه کن. اگر ستاک به مصوت ختم شود — -й می‌افزاییم (chitaj-ut → chitaj). اگر به همخوان با تکیه روی پایانه — -и می‌افزاییم (govor-yat → govori، id-ut → idi). اگر به همخوان بدون تکیه روی پایانه — -ь می‌افزاییم (gotov-yat → gotov'، rezhut → rezh'). صیغهٔ «شما» (مؤدبانه/جمع) -те می‌افزاید: chitajte، govorite. انتخاب نمود: برای یک کنش کامل perf (Otkroj okno! — پنجره را باز کن!)، برای نهی و کنش تکراری impf (Ne otkryvaj! Vsegda zakryvaj dver'). فراخوان مشترک («بیا … کنیم») با davaj(te) + مصدر impf یا + صیغهٔ «ما» perf: davaj pojdyom، davajte pet'.","uk":"Наказовий спосіб виражає прохання, наказ або пораду. Утворюється від основи теперішнього/майбутнього часу (форма «вони»): прибираємо закінчення й дивимося на кінець основи. Якщо основа закінчується на голосний — додаємо -й (читаj-ут → читай). Якщо на приголосний із наголосом на закінченні — додаємо -и (говор-ять → говори, ід-уть → іди). Якщо на приголосний без наголосу на закінченні — додаємо -ь (готов-лять → готовь, ріжуть → ріж). Форма «ви» / ввічлива додає -те: читайте, говоріть. Вибір виду: для завершеної дії — ДВ (Открой окно!), для заборони й повторюваного — НВ (Не открывай! Всегда закрывай дверь). Спільний заклик («давайте зробимо») будується через давай(те) + інфінітив НВ або + форму «ми» ДВ: давай пойдём, давайте петь.","ar_sy":"صيغة الأمر بتعبّر عن طلب أو أمر أو نصيحة. بتتكوّن من جذر المضارع/المستقبل (صيغة «هنّي»): بنشيل النهاية ومنشوف آخر الجذر. إذا الجذر بينتهي بحرف علة — منضيف -й (chitaj-ut → chitaj). إذا بحرف ساكن والنبرة ع النهاية — منضيف -и (govor-yat → govori، id-ut → idi). إذا بحرف ساكن بدون نبرة ع النهاية — منضيف -ь (gotov-yat → gotov'، rezhut → rezh'). صيغة «إنتو»/المؤدّبة بتضيف -те: chitajte، govorite. اختيار الجانب: لفعل تام واحد perf (Otkroj okno! — افتح الشباك!)، للنهي وللمتكرّر impf (Ne otkryvaj! Vsegda zakryvaj dver'). الدعوة المشتركة («خلّينا نعمل») بتنعمل بـdavaj(te) + مصدر impf أو + صيغة «نحنا» perf: davaj pojdyom، davajte pet'."},"tables":[{"caption":{"ru":"Как образовать повелительную форму","de":"Wie man den Imperativ bildet","en":"How to form the imperative","fr":"Comment former l'impératif","fa":"چگونه صیغهٔ امر بسازیم","uk":"Як утворити наказову форму","ar_sy":"كيف نكوّن صيغة الأمر"},"labelHeader":{"ru":"Основа кончается на","de":"Stamm endet auf","en":"Stem ends in","fr":"Le radical finit par","fa":"ستاک ختم می‌شود به","uk":"Основа закінчується на","ar_sy":"الجذر بينتهي بـ"},"columns":[{"ru":"Прибавляем","de":"Wir hängen an","en":"Add","fr":"On ajoute","fa":"می‌افزاییم","uk":"Додаємо","ar_sy":"منضيف"},{"ru":"Ты","de":"Du","en":"You (sg.)","fr":"Tu","fa":"تو","uk":"Ти","ar_sy":"إنت"},{"ru":"Вы / вежл.","de":"Sie / höflich","en":"You (pl./formal)","fr":"Vous","fa":"شما","uk":"Ви / ввічл.","ar_sy":"إنتو / مؤدّب"}],"rows":[{"label":{"ru":"гласную (читаj-ут)","de":"Vokal (čitaj-ut)","en":"vowel (chitaj-ut)","fr":"voyelle (tchitaï-out)","fa":"مصوت (chitaj-ut)","uk":"голосний (читаj-ут)","ar_sy":"حرف علة (chitaj-ut)"},"cells":["-й","читай","читайте"]},{"label":{"ru":"согласную, ударение на конце (говор-ят)","de":"Konsonant, Endbetonung (govor-jat)","en":"consonant, end stress (govor-yat)","fr":"consonne, accent final (govor-iat)","fa":"همخوان، تکیهٔ پایانی (govor-yat)","uk":"приголосний, наголос на кінці (говор-ять)","ar_sy":"ساكن، النبرة بالآخر (govor-yat)"},"cells":["-и","говори","говорите"]},{"label":{"ru":"согласную, без ударения на конце (готов-ят)","de":"Konsonant, keine Endbetonung (gotov-jat)","en":"consonant, no end stress (gotov-yat)","fr":"consonne, sans accent final (gotov-iat)","fa":"همخوان، بدون تکیهٔ پایانی (gotov-yat)","uk":"приголосний, без наголосу на кінці (готов-лять)","ar_sy":"ساكن، بدون نبرة بالآخر (gotov-yat)"},"cells":["-ь","готовь","готовьте"]},{"label":{"ru":"особые / призыв «давай»","de":"Sonderfälle / Aufruf „davaj“","en":"special / call 'davaj'","fr":"cas spéciaux / appel « davaï »","fa":"استثناها / فراخوان «davaj»","uk":"особливі / заклик «давай»","ar_sy":"حالات خاصة / دعوة «davaj»"},"cells":["давай(те) + инф./«мы»","давай пойдём","давайте петь"]}]}],"examples":[{"ru":"Открой окно, пожалуйста, но не открывай дверь — там сквозняк.","de":"Mach bitte das Fenster auf, aber mach die Tür nicht auf — da zieht es.","en":"Open the window, please, but don't open the door — there's a draught.","fr":"Ouvre la fenêtre, s'il te plaît, mais n'ouvre pas la porte — il y a un courant d'air.","fa":"لطفاً پنجره را باز کن، اما در را باز نکن — کوران هوا هست.","uk":"Відчини вікно, будь ласка, але не відчиняй двері — там протяг.","ar_sy":"افتح الشباك لو سمحت، بس ما تفتح الباب — في هوا."},{"ru":"Не волнуйтесь и говорите медленнее, я вас понимаю.","de":"Regen Sie sich nicht auf und sprechen Sie langsamer, ich verstehe Sie.","en":"Don't worry and speak more slowly, I understand you.","fr":"Ne vous inquiétez pas et parlez plus lentement, je vous comprends.","fa":"نگران نباشید و آهسته‌تر صحبت کنید، من شما را می‌فهمم.","uk":"Не хвилюйтеся і говоріть повільніше, я вас розумію.","ar_sy":"ما تقلقوا واحكوا شوي عالمهل، أنا فاهمكن."},{"ru":"Давай встретимся завтра, а давайте пригласим и Анну!","de":"Lass uns morgen treffen, und lasst uns auch Anna einladen!","en":"Let's meet tomorrow, and let's invite Anna too!","fr":"Retrouvons-nous demain, et invitons aussi Anna !","fa":"بیا فردا همدیگر را ببینیم، و بیایید آنا را هم دعوت کنیم!","uk":"Давай зустрінемося завтра, а давайте запросимо й Анну!","ar_sy":"خلّينا نتلاقى بكرا، وخلّينا نعزم آنّا كمان!"}],"hints":{"de":"Bilde den Imperativ IMMER von der „sie“-Form, nicht vom Infinitiv — so vermeidest du Fehler (pisatj → pišut → piši, nicht „pisaj“). Für Aspekt: positive Aufforderung meist perf (Sdelaj!), Verbot mit „ne“ fast immer impf (Ne delaj etogo!).","en":"ALWAYS build the imperative from the 'they' form, not the infinitive — that avoids mistakes (pisat → pishut → pishi, not 'pisay'). For aspect: a positive command is usually perf (Sdelay!), a prohibition with 'ne' is almost always impf (Ne delay etogo!).","fr":"Formez TOUJOURS l'impératif à partir de la forme « ils », pas de l'infinitif — cela évite les erreurs (pisat → pichout → pichi, et non « pissaï »). Pour l'aspect : un ordre positif est en général au perf (Sdelaï !), une interdiction avec « ne » est presque toujours à l'impf (Ne delaï etogo !).","fa":"امر را همیشه از صیغهٔ «آنها» بساز، نه از مصدر — این‌طور از خطا دور می‌مانی (pisat → pishut → pishi، نه «pisaj»). برای نمود: دستور مثبت معمولاً perf (Sdelaj!)، نهی با «ne» تقریباً همیشه impf (Ne delaj etogo!).","uk":"Утворюйте наказ ЗАВЖДИ від форми «вони», а не від інфінітива — так уникнете помилок (писать → пишут → пиши, а не «писай»). Щодо виду: позитивний наказ зазвичай ДВ (Сделай!), заборона з «не» майже завжди НВ (Не делай этого!).","ar_sy":"كوّن الأمر دايمًا من صيغة «هنّي»، مو من المصدر — هيك بتتجنّب الغلط (pisat → pishut → pishi، مو «pisaj»). للجانب: الأمر الإيجابي عادةً perf (Sdelaj!)، والنهي بـ«ne» دايمًا تقريبًا impf (Ne delaj etogo!)."}},
{"id":"uslovnoe-naklonenie","icon":"🕊️","level":"B1","title":{"ru":"Условное наклонение (бы + прошедшее время)","de":"Konditional / Konjunktiv (бы + Vergangenheit)","en":"Conditional / subjunctive (бы + past tense)","fr":"Le conditionnel (бы + passé)","fa":"وجه شرطی (бы + زمان گذشته)","uk":"Умовний спосіб (бы + минулий час)","ar_sy":"صيغة الشرط (бы + الماضي)"},"intro":{"ru":"Условное наклонение образуется просто: глагол в прошедшем времени + частица «бы». Оно выражает нереальные, желаемые или вежливые действия. «Бы» может стоять после глагола или после другого слова: «Я хотел бы» или «Я бы хотел».","de":"Der Konditional wird ganz einfach gebildet: Verb im Präteritum + Partikel «бы». Er drückt irreale, erwünschte oder höfliche Handlungen aus. «Бы» kann nach dem Verb oder nach einem anderen Wort stehen: «Я хотел бы» oder «Я бы хотел».","en":"The conditional is formed very simply: a past-tense verb + the particle «бы». It expresses unreal, wished-for or polite actions. «Бы» may stand after the verb or after another word: «Я хотел бы» or «Я бы хотел».","fr":"Le conditionnel se forme très simplement : verbe au passé + la particule « бы ». Il exprime des actions irréelles, souhaitées ou polies. « Бы » peut suivre le verbe ou un autre mot : « Я хотел бы » ou « Я бы хотел ».","fa":"وجه شرطی خیلی ساده ساخته می‌شود: فعل در زمان گذشته + ذرهٔ «бы». این وجه کارهای غیرواقعی، آرزو شده یا مؤدبانه را بیان می‌کند. «бы» می‌تواند بعد از فعل یا بعد از کلمهٔ دیگری بیاید: «Я хотел бы» یا «Я бы хотел».","uk":"Умовний спосіб утворюється дуже просто: дієслово в минулому часі + частка «бы». Він виражає нереальні, бажані або ввічливі дії. «Бы» може стояти після дієслова або після іншого слова: «Я хотел бы» або «Я бы хотел».","ar_sy":"صيغة الشرط بتتكوّن بشكل بسيط: فعل بالماضي + أداة «бы». بتعبّر عن أفعال غير واقعية أو مرغوبة أو مؤدّبة. «бы» ممكن تجي بعد الفعل أو بعد كلمة تانية: «Я хотел бы» أو «Я бы хотел»."},"tables":[{"caption":{"ru":"Образование условного наклонения","de":"Bildung des Konditionals","en":"Forming the conditional","fr":"Formation du conditionnel","fa":"ساخت وجه شرطی","uk":"Утворення умовного способу","ar_sy":"تكوين صيغة الشرط"},"labelHeader":{"ru":"Лицо / род","de":"Person / Genus","en":"Person / gender","fr":"Personne / genre","fa":"شخص / جنس","uk":"Особа / рід","ar_sy":"الشخص / الجنس"},"columns":[{"ru":"Прошедшее + бы","de":"Vergangenheit + бы","en":"Past + бы","fr":"Passé + бы","fa":"گذشته + бы","uk":"Минулий + бы","ar_sy":"الماضي + бы"}],"rows":[{"label":{"ru":"он (муж.)","de":"er (m.)","en":"he (masc.)","fr":"il (masc.)","fa":"او (مذکر)","uk":"він (чол.)","ar_sy":"هو (مذكر)"},"cells":["он читал бы"]},{"label":{"ru":"она (жен.)","de":"sie (f.)","en":"she (fem.)","fr":"elle (fém.)","fa":"او (مؤنث)","uk":"вона (жін.)","ar_sy":"هي (مؤنث)"},"cells":["она читала бы"]},{"label":{"ru":"они (мн.)","de":"sie (Pl.)","en":"they (pl.)","fr":"ils/elles (pl.)","fa":"آن‌ها (جمع)","uk":"вони (мн.)","ar_sy":"هم (جمع)"},"cells":["они читали бы"]},{"label":{"ru":"вежливо","de":"höflich","en":"polite","fr":"poli","fa":"مؤدبانه","uk":"ввічливо","ar_sy":"بأدب"},"cells":["я хотел бы"]}]}],"examples":[{"ru":"Если бы у меня было время, я бы поехал к морю.","de":"Wenn ich Zeit hätte, würde ich ans Meer fahren.","en":"If I had time, I would go to the sea.","fr":"Si j'avais le temps, j'irais à la mer.","fa":"اگر وقت داشتم، به دریا می‌رفتم.","uk":"Якби я мав час, я б поїхав до моря.","ar_sy":"لو كان عندي وقت، كنت رحت عالبحر."},{"ru":"Я хотел бы стакан воды, пожалуйста.","de":"Ich hätte gern ein Glas Wasser, bitte.","en":"I would like a glass of water, please.","fr":"Je voudrais un verre d'eau, s'il vous plaît.","fa":"من یک لیوان آب می‌خواستم، لطفاً.","uk":"Я хотів би склянку води, будь ласка.","ar_sy":"بدّي كاسة مي، لو سمحت."},{"ru":"На твоём месте я бы не говорил с ним.","de":"An deiner Stelle würde ich nicht mit ihm reden.","en":"In your place I wouldn't talk to him.","fr":"À ta place, je ne lui parlerais pas.","fa":"جای تو بودم با او حرف نمی‌زدم.","uk":"На твоєму місці я б не говорив з ним.","ar_sy":"لو محلّك ما بحكي معو."}],"hints":{"de":"«Бы» ändert sich nie — es bleibt immer gleich; nur das Verb passt sich an Genus und Zahl an. Nach der Konjunktion «если» wird oft «если бы» verwendet.","en":"«Бы» never changes — it stays the same; only the verb agrees in gender and number. After the conjunction «если» you often use «если бы».","fr":"« Бы » ne change jamais — il reste identique ; seul le verbe s'accorde en genre et en nombre. Après la conjonction « если » on emploie souvent « если бы ».","fa":"«бы» هرگز تغییر نمی‌کند — همیشه ثابت است؛ فقط فعل از نظر جنس و شمار مطابقت می‌کند. بعد از حرف ربط «если» اغلب «если бы» به کار می‌رود.","uk":"«Бы» ніколи не змінюється — воно завжди однакове; лише дієслово узгоджується в роді та числі. Після сполучника «если» часто вживають «если бы».","ar_sy":"«бы» ما بتتغيّر أبداً — بتضل نفسها؛ بس الفعل بيتغيّر حسب الجنس والعدد. بعد أداة الشرط «если» منستعمل كتير «если бы»."}},
{"id":"sravnitelnaya-stepen","icon":"📊","level":"B1","title":{"ru":"Сравнительная и превосходная степень","de":"Komparativ und Superlativ","en":"Comparatives and superlatives","fr":"Le comparatif et le superlatif","fa":"درجهٔ برتر و برترین (تفضیلی و عالی)","uk":"Вищий і найвищий ступінь","ar_sy":"صيغة المقارنة والتفضيل"},"intro":{"ru":"Сравнительная степень чаще всего образуется с суффиксом «-ее»: «быстрее», «интереснее». Многие частые слова нестандартны: «хороший → лучше», «плохой → хуже», «большой → больше». Для сравнения используют «чем» или родительный падеж. Превосходная степень образуется словом «самый» + прилагательное: «самый большой».","de":"Der Komparativ wird meist mit dem Suffix «-ее» gebildet: «быстрее», «интереснее». Viele häufige Wörter sind unregelmäßig: «хороший → лучше», «плохой → хуже», «большой → больше». Zum Vergleichen benutzt man «чем» oder den Genitiv. Der Superlativ wird mit «самый» + Adjektiv gebildet: «самый большой».","en":"The comparative is most often formed with the suffix «-ее»: «быстрее», «интереснее». Many common words are irregular: «хороший → лучше», «плохой → хуже», «большой → больше». To compare, use «чем» or the genitive case. The superlative is formed with «самый» + adjective: «самый большой».","fr":"Le comparatif se forme le plus souvent avec le suffixe « -ее » : « быстрее », « интереснее ». Beaucoup de mots courants sont irréguliers : « хороший → лучше », « плохой → хуже », « большой → больше ». Pour comparer, on utilise « чем » ou le génitif. Le superlatif se forme avec « самый » + adjectif : « самый большой ».","fa":"درجهٔ برتر بیشتر با پسوند «-ее» ساخته می‌شود: «быстрее»، «интереснее». خیلی از واژه‌های پرکاربرد بی‌قاعده‌اند: «хороший → лучше»، «плохой → хуже»، «большой → больше». برای مقایسه از «чем» یا حالت اضافی (родительный) استفاده می‌شود. درجهٔ عالی با «самый» + صفت ساخته می‌شود: «самый большой».","uk":"Вищий ступінь найчастіше утворюється суфіксом «-ее»: «быстрее», «интереснее». Багато поширених слів неправильні: «хороший → лучше», «плохой → хуже», «большой → больше». Для порівняння вживають «чем» або родовий відмінок. Найвищий ступінь утворюється словом «самый» + прикметник: «самый большой».","ar_sy":"صيغة المقارنة بتتكوّن غالباً باللاحقة «-ее»: «быстрее»، «интереснее». كتير كلمات شائعة شاذة: «хороший → лучше»، «плохой → хуже»، «большой → больше». للمقارنة منستعمل «чем» أو حالة الجر (родительный). صيغة التفضيل بتتكوّن بكلمة «самый» + الصفة: «самый большой»."},"tables":[{"caption":{"ru":"Частые нестандартные формы","de":"Häufige unregelmäßige Formen","en":"Common irregular forms","fr":"Formes irrégulières fréquentes","fa":"شکل‌های بی‌قاعدهٔ پرکاربرد","uk":"Поширені неправильні форми","ar_sy":"الصيغ الشاذة الشائعة"},"labelHeader":{"ru":"Прилагательное","de":"Adjektiv","en":"Adjective","fr":"Adjectif","fa":"صفت","uk":"Прикметник","ar_sy":"الصفة"},"columns":[{"ru":"Сравнительная","de":"Komparativ","en":"Comparative","fr":"Comparatif","fa":"برتر","uk":"Вищий","ar_sy":"المقارنة"},{"ru":"Превосходная","de":"Superlativ","en":"Superlative","fr":"Superlatif","fa":"عالی","uk":"Найвищий","ar_sy":"التفضيل"}],"rows":[{"label":{"ru":"хороший","de":"gut","en":"good","fr":"bon","fa":"خوب","uk":"хороший","ar_sy":"منيح"},"cells":["лучше","самый хороший / лучший"]},{"label":{"ru":"плохой","de":"schlecht","en":"bad","fr":"mauvais","fa":"بد","uk":"поганий","ar_sy":"عاطل"},"cells":["хуже","самый плохой / худший"]},{"label":{"ru":"большой","de":"groß","en":"big","fr":"grand","fa":"بزرگ","uk":"великий","ar_sy":"كبير"},"cells":["больше","самый большой"]},{"label":{"ru":"маленький","de":"klein","en":"small","fr":"petit","fa":"کوچک","uk":"маленький","ar_sy":"زغير"},"cells":["меньше","самый маленький"]}]},{"caption":{"ru":"Две модели сравнения","de":"Zwei Vergleichsmodelle","en":"Two comparison patterns","fr":"Deux modèles de comparaison","fa":"دو الگوی مقایسه","uk":"Дві моделі порівняння","ar_sy":"طريقتين للمقارنة"},"labelHeader":{"ru":"Модель","de":"Modell","en":"Pattern","fr":"Modèle","fa":"الگو","uk":"Модель","ar_sy":"الطريقة"},"columns":[{"ru":"Пример","de":"Beispiel","en":"Example","fr":"Exemple","fa":"مثال","uk":"Приклад","ar_sy":"مثال"}],"rows":[{"label":{"ru":"с «чем»","de":"mit «чем»","en":"with «чем»","fr":"avec « чем »","fa":"با «чем»","uk":"з «чем»","ar_sy":"مع «чем»"},"cells":["Он старше, чем я."]},{"label":{"ru":"родительный","de":"Genitiv","en":"genitive","fr":"génitif","fa":"حالت اضافی","uk":"родовий","ar_sy":"حالة الجر"},"cells":["Он старше меня."]}]}],"examples":[{"ru":"Москва больше, чем мой родной город.","de":"Moskau ist größer als meine Heimatstadt.","en":"Moscow is bigger than my home town.","fr":"Moscou est plus grande que ma ville natale.","fa":"مسکو از شهر زادگاه من بزرگ‌تر است.","uk":"Москва більша, ніж моє рідне місто.","ar_sy":"موسكو أكبر من مدينتي الأصلية."},{"ru":"Это самый интересный фильм года.","de":"Das ist der interessanteste Film des Jahres.","en":"This is the most interesting film of the year.","fr":"C'est le film le plus intéressant de l'année.","fa":"این جالب‌ترین فیلم سال است.","uk":"Це найцікавіший фільм року.","ar_sy":"هادا أهمّ فيلم بالسنة."},{"ru":"Сегодня погода лучше, чем вчера.","de":"Heute ist das Wetter besser als gestern.","en":"Today the weather is better than yesterday.","fr":"Aujourd'hui, il fait meilleur qu'hier.","fa":"امروز هوا از دیروز بهتر است.","uk":"Сьогодні погода краща, ніж учора.","ar_sy":"اليوم الطقس أحسن من مبارح."}],"hints":{"de":"Die einfache Komparativform («быстрее», «больше») ist unveränderlich — sie passt sich nicht an Genus oder Fall an. «Самый» dagegen wird wie das Adjektiv dekliniert.","en":"The simple comparative form («быстрее», «больше») is invariable — it does not agree in gender or case. «Самый», by contrast, is declined like the adjective.","fr":"La forme comparative simple (« быстрее », « больше ») est invariable — elle ne s'accorde ni en genre ni en cas. « Самый », en revanche, se décline comme l'adjectif.","fa":"شکل سادهٔ برتر («быстрее»، «больше») تغییرناپذیر است — از نظر جنس یا حالت مطابقت نمی‌کند. اما «самый» مثل صفت صرف می‌شود.","uk":"Проста форма вищого ступеня («быстрее», «больше») незмінна — вона не узгоджується в роді чи відмінку. Натомість «самый» відмінюється як прикметник.","ar_sy":"صيغة المقارنة البسيطة («быстрее»، «больше») ما بتتغيّر — ما بتطابق بالجنس ولا الحالة. بس «самый» بينصرف متل الصفة."}},
{"id":"vozvratnye-glagoly","icon":"🔁","level":"B1","title":{"ru":"Возвратные глаголы (-ся / -сь)","de":"Reflexive Verben (-ся / -сь)","en":"Reflexive verbs (-ся / -сь)","fr":"Les verbes pronominaux (-ся / -сь)","fa":"افعال انعکاسی (-ся / -сь)","uk":"Зворотні дієслова (-ся / -сь)","ar_sy":"الأفعال الانعكاسية (-ся / -сь)"},"intro":{"ru":"Возвратные глаголы оканчиваются на «-ся» (после согласного) или «-сь» (после гласного): «мыться — я моюсь». Они бывают собственно возвратными (действие на себя), взаимными (друг друга), пассивными, а некоторые всегда с «-ся» и без него не существуют (например, «улыбаться», «бояться»).","de":"Reflexive Verben enden auf «-ся» (nach Konsonant) oder «-сь» (nach Vokal): «мыться — я моюсь». Sie können echt reflexiv sein (Handlung auf sich selbst), reziprok (einander), passiv, und manche existieren nur mit «-ся» (z. B. «улыбаться», «бояться»).","en":"Reflexive verbs end in «-ся» (after a consonant) or «-сь» (after a vowel): «мыться — я моюсь». They can be truly reflexive (action on oneself), reciprocal (each other), passive, and some exist only with «-ся» (e.g. «улыбаться», «бояться»).","fr":"Les verbes pronominaux se terminent par « -ся » (après une consonne) ou « -сь » (après une voyelle) : « мыться — я моюсь ». Ils peuvent être proprement réfléchis (action sur soi-même), réciproques (l'un l'autre), passifs, et certains n'existent qu'avec « -ся » (par ex. « улыбаться », « бояться »).","fa":"افعال انعکاسی به «-ся» (بعد از صامت) یا «-сь» (بعد از مصوت) ختم می‌شوند: «мыться — я моюсь». این افعال می‌توانند واقعاً انعکاسی (کار روی خود)، متقابل (همدیگر)، مجهول باشند و برخی فقط با «-ся» وجود دارند (مثلاً «улыбаться»، «бояться»).","uk":"Зворотні дієслова закінчуються на «-ся» (після приголосного) або «-сь» (після голосного): «мыться — я моюсь». Вони бувають власне зворотними (дія на себе), взаємними (одне одного), пасивними, а деякі існують лише з «-ся» (наприклад, «улыбаться», «бояться»).","ar_sy":"الأفعال الانعكاسية بتنتهي بـ«-ся» (بعد حرف ساكن) أو «-сь» (بعد حرف متحرّك): «мыться — я моюсь». ممكن تكون انعكاسية حقيقية (الفعل على النفس)، أو تبادلية (بعض)، أو مجهولة، وفي أفعال ما بتنوجد إلا مع «-ся» (متل «улыбаться»، «бояться»)."},"tables":[{"caption":{"ru":"Типы возвратных глаголов","de":"Typen reflexiver Verben","en":"Types of reflexive verbs","fr":"Types de verbes pronominaux","fa":"انواع افعال انعکاسی","uk":"Типи зворотних дієслів","ar_sy":"أنواع الأفعال الانعكاسية"},"labelHeader":{"ru":"Тип","de":"Typ","en":"Type","fr":"Type","fa":"نوع","uk":"Тип","ar_sy":"النوع"},"columns":[{"ru":"Глагол","de":"Verb","en":"Verb","fr":"Verbe","fa":"فعل","uk":"Дієслово","ar_sy":"الفعل"}],"rows":[{"label":{"ru":"возвратный (действие на себя)","de":"reflexiv (Handlung auf sich)","en":"reflexive (action on oneself)","fr":"réfléchi (action sur soi)","fa":"انعکاسی (کار روی خود)","uk":"зворотний (дія на себе)","ar_sy":"انعكاسي (الفعل على النفس)"},"cells":["мыться"]},{"label":{"ru":"взаимный (друг друга)","de":"reziprok (einander)","en":"reciprocal (each other)","fr":"réciproque (l'un l'autre)","fa":"متقابل (همدیگر)","uk":"взаємний (одне одного)","ar_sy":"تبادلي (بعضهم)"},"cells":["встречаться"]},{"label":{"ru":"пассивный","de":"passiv","en":"passive","fr":"passif","fa":"مجهول","uk":"пасивний","ar_sy":"مجهول"},"cells":["дом строится"]},{"label":{"ru":"только «-ся»","de":"nur «-ся»","en":"only «-ся»","fr":"seulement « -ся »","fa":"فقط «-ся»","uk":"лише «-ся»","ar_sy":"فقط «-ся»"},"cells":["улыбаться"]}]},{"caption":{"ru":"Спряжение: «учиться» (учить себя)","de":"Konjugation: «учиться» (lernen)","en":"Conjugation: «учиться» (to study)","fr":"Conjugaison : « учиться » (étudier)","fa":"صرف: «учиться» (درس خواندن)","uk":"Дієвідміна: «учиться» (навчатися)","ar_sy":"تصريف: «учиться» (يتعلّم)"},"labelHeader":{"ru":"Лицо","de":"Person","en":"Person","fr":"Personne","fa":"شخص","uk":"Особа","ar_sy":"الشخص"},"columns":[{"ru":"Форма","de":"Form","en":"Form","fr":"Forme","fa":"شکل","uk":"Форма","ar_sy":"الصيغة"}],"rows":[{"label":{"ru":"я","de":"ich","en":"I","fr":"je","fa":"من","uk":"я","ar_sy":"أنا"},"cells":["учусь"]},{"label":{"ru":"ты","de":"du","en":"you (sg.)","fr":"tu","fa":"تو","uk":"ти","ar_sy":"إنت"},"cells":["учишься"]},{"label":{"ru":"он / она","de":"er / sie","en":"he / she","fr":"il / elle","fa":"او","uk":"він / вона","ar_sy":"هو / هي"},"cells":["учится"]},{"label":{"ru":"они","de":"sie (Pl.)","en":"they","fr":"ils / elles","fa":"آن‌ها","uk":"вони","ar_sy":"هم"},"cells":["учатся"]}]}],"examples":[{"ru":"Каждое утро я умываюсь холодной водой.","de":"Jeden Morgen wasche ich mich mit kaltem Wasser.","en":"Every morning I wash with cold water.","fr":"Chaque matin, je me lave à l'eau froide.","fa":"هر صبح با آب سرد صورتم را می‌شویم.","uk":"Щоранку я вмиваюся холодною водою.","ar_sy":"كل صبح بغسل وجّي بمي باردة."},{"ru":"Мы встречаемся с друзьями по субботам.","de":"Wir treffen uns samstags mit Freunden.","en":"We meet with friends on Saturdays.","fr":"Nous nous retrouvons avec des amis le samedi.","fa":"ما شنبه‌ها با دوستان همدیگر را می‌بینیم.","uk":"Ми зустрічаємося з друзями по суботах.","ar_sy":"منلتقي مع الأصحاب كل سبت."},{"ru":"Дети боятся темноты.","de":"Die Kinder fürchten sich vor der Dunkelheit.","en":"The children are afraid of the dark.","fr":"Les enfants ont peur du noir.","fa":"بچه‌ها از تاریکی می‌ترسند.","uk":"Діти бояться темряви.","ar_sy":"الولاد بيخافوا من العتمة."}],"hints":{"de":"Merke: «-ся» wird nach einem Konsonanten oder «ь» benutzt, «-сь» nach einem Vokal. So heißt es «я учусь», aber «ты учишься». Reflexive Verben haben nie ein direktes Akkusativobjekt.","en":"Note: «-ся» is used after a consonant or «ь», and «-сь» after a vowel. So it is «я учусь» but «ты учишься». Reflexive verbs never take a direct accusative object.","fr":"Remarque : « -ся » s'emploie après une consonne ou « ь », et « -сь » après une voyelle. On dit donc « я учусь » mais « ты учишься ». Les verbes pronominaux n'ont jamais de complément direct à l'accusatif.","fa":"توجه: «-ся» بعد از صامت یا «ь» می‌آید و «-сь» بعد از مصوت. پس می‌گوییم «я учусь» ولی «ты учишься». افعال انعکاسی هرگز مفعول مستقیم در حالت مفعولی نمی‌گیرند.","uk":"Зверніть увагу: «-ся» вживається після приголосного або «ь», а «-сь» після голосного. Тому «я учусь», але «ты учишься». Зворотні дієслова ніколи не мають прямого додатка в знахідному відмінку.","ar_sy":"لاحظ: «-ся» بتنستعمل بعد حرف ساكن أو «ь»، و«-сь» بعد حرف متحرّك. لهيك منقول «я учусь» بس «ты учишься». الأفعال الانعكاسية ما بتاخد مفعول به مباشر بحالة النصب."}},
{"id":"slozhnye-predlozheniya","icon":"🔗","level":"B1","title":{"ru":"Сложные предложения (союзы)","de":"Komplexe Sätze (Konjunktionen)","en":"Complex sentences (conjunctions)","fr":"Les phrases complexes (conjonctions)","fa":"جمله‌های مرکب (حروف ربط)","uk":"Складні речення (сполучники)","ar_sy":"الجمل المركّبة (أدوات الربط)"},"intro":{"ru":"Сложные предложения соединяют части с помощью союзов и союзных слов. «Который» вводит относительное придаточное и изменяется по роду, числу и падежу. «Чтобы» выражает цель, «потому что» — причину, «поэтому» — следствие, «когда» — время, «если» — условие.","de":"Komplexe Sätze verbinden Teile mit Konjunktionen und Relativwörtern. «Который» leitet einen Relativsatz ein und verändert sich nach Genus, Zahl und Fall. «Чтобы» drückt das Ziel aus, «потому что» den Grund, «поэтому» die Folge, «когда» die Zeit, «если» die Bedingung.","en":"Complex sentences join clauses with conjunctions and relative words. «Который» introduces a relative clause and changes for gender, number and case. «Чтобы» expresses purpose, «потому что» reason, «поэтому» result, «когда» time, «если» condition.","fr":"Les phrases complexes relient des propositions par des conjonctions et des pronoms relatifs. « Который » introduit une relative et varie selon le genre, le nombre et le cas. « Чтобы » exprime le but, « потому что » la cause, « поэтому » la conséquence, « когда » le temps, « если » la condition.","fa":"جمله‌های مرکب بخش‌ها را با حروف ربط و کلمات ربطی به هم وصل می‌کنند. «который» جملهٔ موصولی می‌آورد و بر حسب جنس، شمار و حالت تغییر می‌کند. «чтобы» هدف، «потому что» علت، «поэтому» نتیجه، «когда» زمان و «если» شرط را بیان می‌کند.","uk":"Складні речення з'єднують частини за допомогою сполучників і сполучних слів. «Который» вводить підрядне означальне й змінюється за родом, числом і відмінком. «Чтобы» виражає мету, «потому что» — причину, «поэтому» — наслідок, «когда» — час, «если» — умову.","ar_sy":"الجمل المركّبة بتربط الأجزاء بأدوات ربط وكلمات موصولة. «который» بيجيب جملة موصولة وبيتغيّر حسب الجنس والعدد والحالة. «чтобы» بتعبّر عن الهدف، «потому что» عن السبب، «поэтому» عن النتيجة، «когда» عن الزمن، و«если» عن الشرط."},"tables":[{"caption":{"ru":"Основные союзы и союзные слова","de":"Wichtige Konjunktionen und Relativwörter","en":"Main conjunctions and relative words","fr":"Principales conjonctions et mots relatifs","fa":"حروف ربط و کلمات ربطی اصلی","uk":"Основні сполучники та сполучні слова","ar_sy":"أهم أدوات الربط والكلمات الموصولة"},"labelHeader":{"ru":"Функция","de":"Funktion","en":"Function","fr":"Fonction","fa":"کارکرد","uk":"Функція","ar_sy":"الوظيفة"},"columns":[{"ru":"Союз","de":"Konjunktion","en":"Conjunction","fr":"Conjonction","fa":"حرف ربط","uk":"Сполучник","ar_sy":"أداة الربط"}],"rows":[{"label":{"ru":"относительное","de":"Relativsatz","en":"relative clause","fr":"proposition relative","fa":"جملهٔ موصولی","uk":"означальне (відносне)","ar_sy":"جملة موصولة"},"cells":["который"]},{"label":{"ru":"цель","de":"Zweck / Absicht","en":"purpose","fr":"but","fa":"هدف","uk":"мета","ar_sy":"الهدف"},"cells":["чтобы"]},{"label":{"ru":"причина","de":"Grund","en":"reason / cause","fr":"cause","fa":"علت","uk":"причина","ar_sy":"السبب"},"cells":["потому что"]},{"label":{"ru":"следствие","de":"Folge","en":"result / consequence","fr":"conséquence","fa":"نتیجه","uk":"наслідок","ar_sy":"النتيجة"},"cells":["поэтому"]},{"label":{"ru":"время / условие","de":"Zeit / Bedingung","en":"time / condition","fr":"temps / condition","fa":"زمان / شرط","uk":"час / умова","ar_sy":"الزمن / الشرط"},"cells":["когда / если"]}]}],"examples":[{"ru":"Это книга, которую я читал вчера.","de":"Das ist das Buch, das ich gestern gelesen habe.","en":"This is the book that I read yesterday.","fr":"C'est le livre que j'ai lu hier.","fa":"این همان کتابی است که دیروز خواندم.","uk":"Це книга, яку я читав учора.","ar_sy":"هادا الكتاب يلّي قريتو مبارح."},{"ru":"Я учу русский, чтобы говорить с бабушкой.","de":"Ich lerne Russisch, um mit meiner Oma zu sprechen.","en":"I'm learning Russian in order to talk with my grandmother.","fr":"J'apprends le russe pour parler avec ma grand-mère.","fa":"روسی یاد می‌گیرم تا با مادربزرگم حرف بزنم.","uk":"Я вивчаю російську, щоб говорити з бабусею.","ar_sy":"عم تعلّم روسي مشان احكي مع ستّي."},{"ru":"Я остался дома, потому что шёл дождь.","de":"Ich blieb zu Hause, weil es regnete.","en":"I stayed home because it was raining.","fr":"Je suis resté à la maison parce qu'il pleuvait.","fa":"خانه ماندم چون باران می‌آمد.","uk":"Я залишився вдома, бо йшов дощ.","ar_sy":"ضلّيت بالبيت لأنو كان في شتي."}],"hints":{"de":"«Который» richtet sich im Genus und in der Zahl nach dem Bezugswort, aber sein Fall hängt von seiner Rolle im Nebensatz ab. Vor «который», «чтобы» und «потому что» steht immer ein Komma.","en":"«Который» agrees in gender and number with the noun it refers to, but its case depends on its role in the subordinate clause. A comma always precedes «который», «чтобы» and «потому что».","fr":"« Который » s'accorde en genre et en nombre avec le nom auquel il renvoie, mais son cas dépend de son rôle dans la subordonnée. On met toujours une virgule avant « который », « чтобы » et « потому что ».","fa":"«который» از نظر جنس و شمار با اسمی که به آن اشاره دارد مطابقت می‌کند، اما حالت آن به نقشش در جملهٔ پیرو بستگی دارد. پیش از «который»، «чтобы» و «потому что» همیشه ویرگول می‌آید.","uk":"«Который» узгоджується в роді та числі з іменником, до якого відноситься, але його відмінок залежить від ролі в підрядному реченні. Перед «который», «чтобы» і «потому что» завжди ставиться кома.","ar_sy":"«который» بيطابق بالجنس والعدد الاسم يلّي بيرجع عليه، بس حالته بتعتمد على دورو بالجملة التابعة. قبل «который» و«чтобы» و«потому что» دايماً في فاصلة."}}
];
